window.QB_G7_C3_S3.push(
  {c:'地形',q:'大陆漂移学说认为，大约多少亿年前，各大陆是连在一起的？',o:['1亿年前','2亿年前','5亿年前','10亿年前'],a:1,e:'魏格纳的大陆漂移假说认为，大约2亿年前，地球各大陆是一块连在一起的超大陆（泛大陆），后来逐渐分裂漂移到今天的位置。'},
  {c:'地形',q:'支持大陆漂移假说的证据不包括？',o:['南美洲东岸与非洲西岸轮廓吻合','两侧陆地古老地层和生物化石相似','大西洋两岸相距遥远','南极洲发现煤炭（说明曾为温暖陆地）'],a:2,e:'大陆漂移的证据：①两岸海岸轮廓吻合②两岸地层和化石相同（如舌羊齿化石）③南极洲有煤（说明曾在温暖地带）。大西洋两岸相距遥远恰恰是漂移的结果，不是证据。'},
  {c:'地形',q:'板块构造学说中，板块运动的驱动力是？',o:['地球自转','地球内部热能驱动的地幔对流','月球引力（潮汐力）','太阳引力'],a:1,e:'板块运动的驱动力是地球内部放射性元素衰变产生的热能，驱动地幔物质的对流运动，带动板块在地球表面缓慢移动（每年几厘米）。'},
  {c:'地形',q:'红海在不断扩大，这说明？',o:['非洲板块与印度洋板块在碰撞','亚欧板块与非洲板块在碰撞','非洲板块与亚欧板块在张裂分离','太平洋板块在缩小'],a:2,e:'红海位于非洲板块与印度洋板块（或亚欧板块）之间的张裂处，板块分离→地壳拉开→红海越来越宽，未来可能发展成更大的海洋。'},
  {c:'地形',q:'太平洋周围多地震，原因是？',o:['太平洋面积大','太平洋周围板块交界多，地壳活动活跃','太平洋水深','太平洋气候特殊'],a:1,e:'太平洋周围（环太平洋地带）是多个板块（太平洋板块、亚欧板块、北美板块等）的交界处，地壳活动强烈，是地震和火山最集中的"环太平洋火山地震带"。'},
  {c:'地形',q:'板块碰撞挤压形成山脉，板块张裂可能形成？',o:['山脉和高原','裂谷和海洋（如东非大裂谷→红海→将来的大洋）','平原','沙漠'],a:1,e:'板块张裂→地壳变薄断裂→形成裂谷（如东非大裂谷）；裂谷进一步扩大→被海水注入→形成海洋（如红海）→最终扩展成大洋（如大西洋的形成过程）。'},
  {c:'地形',q:'中国台湾的地震频繁，原因是？',o:['台湾岛是火山岛','台湾位于亚欧板块与太平洋板块交界处附近','台湾气候多雨','台湾海拔高'],a:1,e:'台湾位于亚欧板块与菲律宾板块（太平洋板块系）的消亡边界附近，地壳活动剧烈，是中国地震最频繁的地区之一。'},
  {c:'地形',q:'地球上最深的海沟——马里亚纳海沟，位于哪两个板块的交界处？',o:['亚欧板块与非洲板块','太平洋板块与亚欧板块（菲律宾板块）','美洲板块与太平洋板块','印度洋板块与南极洲板块'],a:1,e:'马里亚纳海沟（约11034m）位于西太平洋，是太平洋板块与菲律宾板块（亚欧板块边缘）碰撞挤压（俯冲）处，板块俯冲→地壳向下弯曲→形成深海沟。'}
);

/* ── 七上·第四章·第一节 多变的天气（补充 +9） ── */
window.QB_G7_C4_S1.push(
  {c:'气候',q:'以下关于天气和气候的区分，正确的是？',o:['"北京四季分明"——天气；"今天北京晴，最高温25℃"——气候','两者没有区别','前者气候，后者天气','天气可以预报，气候无法研究'],a:2,e:'"北京四季分明"是长期的大气平均状况，属气候；"今天晴，25℃"是短时间的大气状况，属天气。关键：气候=长期平均，天气=当前短暂。'},
  {c:'气候',q:'气象台发布暴雨红色预警，说明？',o:['未来无降雨','降雨已经停止','预计将出现强烈降雨，危害最严重（红色最高级）','只是一般性降雨'],a:2,e:'气象预警分四级：蓝色→黄色→橙色→红色（最高级、最严重）。红色预警说明灾害风险极高，需立即采取防灾措施。'},
  {c:'气候',q:'气象观测中，降水量是用什么量具测量的？',o:['温度计','气压计','雨量器（量筒）','风向标'],a:2,e:'降水量用雨量器（标准量筒，口径固定，收集雨水后读取毫米数）测量，单位为毫米（mm）。气温用温度计，气压用气压计，风向用风向标。'},
  {c:'气候',q:'风的形成根本原因是？',o:['地球自转','温度差异导致气压差，气流从高压流向低压','海陆差异','地形影响'],a:1,e:'风的形成：地面受热不均→温度差异→气压差异（热地气压低，冷地气压高）→空气从高压区流向低压区→形成风。风向：高压→低压。'},
  {c:'气候',q:'天气预报中"气温最低℃"是指？',o:['一天中任意时刻的气温','一天中最冷时刻（通常是日出前后）的气温','正午最高时刻的气温','平均气温'],a:1,e:'最低气温通常出现在日出前后（约4-6时），此时太阳还未照射地面，地面散热后温度最低。最高气温通常在午后（约14时）。'},
  {c:'气候',q:'\"春捂秋冻\"中"秋冻"的地理依据是？',o:['秋天气候不变化','秋天气温下降，适当接受寒冷刺激有助增强抵抗力','秋天不需要穿衣','秋天气温升高'],a:1,e:'"秋冻"意味着秋季气温逐渐降低，适度不过早增添衣物，让身体逐渐适应温差，提高抗寒能力。这与气候逐渐由热转凉的规律有关。'},
  {c:'气候',q:'沙尘暴天气应如何正确应对？',o:['开窗通风','在室外戴口罩护目镜，尽量减少外出，关好门窗','多到户外活动','打开窗户让沙尘进来平衡内外压力'],a:1,e:'沙尘暴时：①减少外出②必须外出时戴口罩、护目镜③关好门窗，避免沙尘进入室内④行驶中降速开危险灯。'},
  {c:'气候',q:'台风带来的灾害包括？',o:['只有强风破坏','只有暴雨洪涝','强风+暴雨+风暴潮（海浪上涌），三种灾害叠加','只有沿海地区受影响'],a:2,e:'台风（热带气旋）的三大灾害：①强风（可达12级以上）②暴雨（引发洪涝）③风暴潮（海面上涌淹没沿岸）。三者叠加，危害极大。'},
  {c:'气候',q:'天气预报中，PM2.5指数属于哪类信息？',o:['气温信息','降水预报','大气质量（空气污染）信息','风向信息'],a:2,e:'PM2.5（细颗粒物，直径≤2.5微米）是大气污染的重要指标，数值越高空气质量越差（雾霾严重）。现代天气预报除气象要素外，还包括空气质量指数（AQI）。'}
);

/* ── 七上·第四章·第二节 气温的变化与分布（补充 +9） ── */
window.QB_G7_C4_S2.push(
  {c:'气候',q:'气温日变化中，一天中气温最高出现在？',o:['正午12时','午后14时（约）','日出时','日落时'],a:1,e:'正午太阳高度最大但地面还在继续吸热，热量仍在积累，午后14时左右地面温度（气温）达到最高；此后散热>吸热，气温开始下降。'},
  {c:'气候',q:'年平均气温最高的大洲是？',o:['亚洲','非洲','南美洲','大洋洲'],a:1,e:'非洲大部分位于热带（南北回归线之间约80%），年均气温最高，是世界上最热的大洲。撒哈拉沙漠局部曾达57.8℃（地表温度更高）。'},
  {c:'气候',q:'气温的年较差（最热月与最冷月均温之差）最大的地区是？',o:['热带雨林地区','温带大陆性气候区（大陆内部中高纬）','沿海温带海洋性气候区','赤道附近'],a:1,e:'温带大陆性气候（中纬度内陆）受海洋影响小，冬冷夏热，年较差很大（可达50℃以上）。海洋性气候和热带地区气温年较差小。'},
  {c:'气候',q:'海拔3000米的山顶，与山脚（海拔100米）相比，气温大约低多少？',o:['约10℃','约17.4℃（约18℃）','约5℃','约30℃'],a:1,e:'对流层内每升高1000m气温降约6℃。3000-100=2900m，降温约2.9×6=17.4℃。所以山顶气温比山脚低约17~18℃。'},
  {c:'气候',q:'同纬度地区，夏季大陆气温比海洋？',o:['低','高','相同','无法比较'],a:1,e:'夏季陆地吸热快升温快，比同纬度海洋气温高（等温线向高纬弯曲）；冬季陆地散热快，比海洋气温低（等温线向低纬弯曲）。这是"海陆热力差异"。'},
  {c:'气候',q:'下列哪个城市气温年较差最小？',o:['哈尔滨（北方大陆内部）','北京','上海','海口（热带岛屿城市）'],a:3,e:'海口位于海南岛，纬度低（约20°N），全年高温，受海洋调节，气温年较差最小（约10℃以内）。哈尔滨气温年较差可达40℃以上。'},
  {c:'气候',q:'等温线从南向北数值逐渐降低，说明该地区位于？',o:['南半球，气温由北向南升高','北半球，气温由南向北降低','赤道附近','南极附近'],a:1,e:'北半球气温从低纬（南）→高纬（北）逐渐降低，所以等温线从南到北数值减小。南半球相反（从北到南降低）。'},
  {c:'气候',q:'为什么夏天山上比山下凉爽？',o:['山上风大','山上云多遮住阳光','对流层气温随海拔升高而降低（约6℃/1000m）','山上湿度大'],a:2,e:'对流层内，海拔越高气温越低（每升高1000m降约6℃），所以山顶气温比山脚低。这也是"高山气候"垂直分带的原因。'},
  {c:'气候',q:'气温由赤道向两极逐渐降低的根本原因是？',o:['海陆分布差异','纬度不同，获得的太阳辐射量不同（低纬多高纬少）','海拔不同','洋流影响'],a:1,e:'赤道地区阳光直射（太阳高度角大），单位面积获热多；两极地区斜射，单位面积获热少；这是气温从赤道向两极降低的根本原因（纬度因素）。'}
);

/* ── 七上·第四章·第三节 降水的变化与分布（补充 +10） ── */
window.QB_G7_C4_S3.push(
  {c:'气候',q:'世界上年降水量最多的地区通常分布在？',o:['温带大陆内部','赤道地区和山地迎风坡','两极地区','热带沙漠'],a:1,e:'赤道对流旺盛，年降水>2000mm；山地迎风坡（地形雨）降水丰富，如乞拉朋齐（年均>10000mm）。这两类是全球降水最多的地区。'},
  {c:'气候',q:'下列关于降水量测量，正确的是？',o:['用温度计测量','用雨量器测量，单位毫米（mm）','用气压计测量','降水量无法测量'],a:1,e:'降水量用雨量器（圆筒形，收集一定时间内的降水），用量筒读取毫米数。年降水量是全年各月降水量之和。'},
  {c:'气候',q:'季风降水的特征是？',o:['全年均匀分布','集中在夏季（或特定季节），季节差异大','全年持续','只在热带出现'],a:1,e:'季风气候降水集中夏季（夏季风从海洋带来水汽），旱雨两季明显。温带海洋性气候降水全年较均匀。'},
  {c:'气候',q:'下列哪种降水类型多出现在赤道附近？',o:['锋面雨','地形雨','对流雨（热对流降水）','台风雨'],a:2,e:'对流雨：赤道地区地面强烈受热→空气大量蒸发上升→急剧冷却凝结→强降雨（常伴雷电）。多发生在午后，以热带为主。'},
  {c:'气候',q:'大陆内部（中纬度）降水少的原因是？',o:['纬度高','距海远，水汽来源少','海拔高','地形影响'],a:1,e:'大陆内部远离海洋，水汽难以输送进来，降水量少。"距海远近"是影响降水的重要因素，也是温带大陆性气候形成的原因之一。'},
  {c:'气候',q:'"巴山夜雨涨秋池"中，夜晚降雨多的山地原因是？',o:['夜晚温度低所以降雨','山谷夜晚谷地气流上升（山谷风），易产生降水','夜晚风大带来水汽','与科学无关，只是诗歌'],a:1,e:'山谷地形中，白天山坡吸热快（上升气流）→谷风；夜晚山坡散热快（下沉气流）→山风。夜晚山谷中气流辐合上升，加上山区湿润，容易夜间降雨，形成"巴山夜雨"。'},
  {c:'气候',q:'影响降水分布的因素中，"南美洲安第斯山脉西坡降水多，东坡降水少"体现了？',o:['纬度位置的影响','海陆位置的影响','地形（迎风坡/背风坡）的影响','洋流的影响'],a:2,e:'安第斯山西坡是来自太平洋湿润气流的迎风坡，降水丰富；东坡是背风坡，气流下沉干燥，降水少（如巴塔哥尼亚沙漠）。这是地形对降水的影响。'},
  {c:'气候',q:'世界年降水量分布规律：赤道多→副热带少→温带中纬多→极地少，其中副热带少雨的原因是？',o:['距海远','受副热带高压控制，盛行下沉气流，不易成云致雨','纬度太高','海拔太高'],a:1,e:'副热带（南北纬30°附近）受副热带高压控制，空气下沉增温，水汽不易凝结，降水少，形成热带沙漠（如撒哈拉、澳大利亚中西部沙漠）。'},
  {c:'气候',q:'年降水量分布图上，等降水量线密集处说明？',o:['降水量均匀','降水量变化大（空间差异大）','降水量为零','降水量最多'],a:1,e:'等降水量线（等雨量线）密集处，表示单位距离内降水量变化大（空间梯度大）；稀疏处变化小。类比等高线：密集=变化快，稀疏=变化慢。'},
  {c:'气候',q:'我国北方降水以夏季为主，南方四季降水较多，其主要原因是？',o:['地形影响','季风影响（夏季风强弱和影响时间长短不同）','纬度影响','洋流影响'],a:1,e:'北方受夏季风影响时间短，降水集中夏季且总量较少；南方受夏季风影响时间长，且受其他气流影响，四季降水较多。这是季风气候的特征。'}
);

/* ── 七上·第四章·第四节 世界的气候（补充 +9） ── */
window.QB_G7_C4_S4.push(
  {c:'气候',q:'热带季风气候的降水特征是？',o:['全年多雨无干季','夏季多雨（6-9月），冬季干燥，旱雨两季分明','全年干旱','降水集中在冬季'],a:1,e:'热带季风气候（印度、东南亚）：夏季西南季风带来丰沛降水（雨季），冬季受东北风影响干燥（旱季），旱雨两季分明，年降水量1500-2000mm以上。'},
  {c:'气候',q:'温带大陆性气候的分布规律是？',o:['大陆东岸中纬度','大陆西岸低纬度','中纬度大陆内部（远离海洋）','高纬度沿海'],a:2,e:'温带大陆性气候分布在中纬度（40°-60°）大陆内部，远离海洋，水汽稀少：冬冷夏热，气温年较差大，降水少，集中夏季。如中国西北、中亚、北美中部。'},
  {c:'气候',q:'下列气候类型中，没有明显旱季的是？',o:['热带季风气候','热带草原气候','温带海洋性气候','地中海气候'],a:2,e:'温带海洋性气候（西欧等）终年受西风影响，全年温和湿润，降水均匀，没有明显旱季。其他三种都有明显的旱（干）季。'},
  {c:'气候',q:'高山气候的主要特征是？',o:['全年高温多雨','气候垂直分带明显（"一山有四季"），气温随海拔升高而降低','全年干旱','与同纬度平原气候相同'],a:1,e:'高山气候（山地气候）：随海拔升高气温降低，降水先增后减，植被出现垂直分布带（从山脚到山顶：常绿阔叶林→针叶林→高山草甸→冰雪）。'},
  {c:'气候',q:'非洲的气候类型分布呈现以赤道为轴南北对称的规律，赤道附近是热带雨林气候，向两侧依次是？',o:['热带草原→热带沙漠→地中海→温带海洋','热带沙漠→热带草原→地中海','温带→热带','热带草原→温带大陆'],a:0,e:'非洲气候类型由赤道向两极对称分布：热带雨林（赤道）→热带草原（约5°-15°）→热带沙漠（约15°-30°）→地中海气候（约30°-40°沿海）→温带海洋（南非最南端）。'},
  {c:'气候',q:'气候与农业生产的关系：水稻的种植要求气候条件是？',o:['高温干旱','低温少雨','高温多雨（热量充足，水分充沛）','四季分明，冬冷夏热'],a:2,e:'水稻是喜温喜湿作物，需要高温多雨的气候（夏季高温≥20℃，年降水量≥1000mm），主要种植在亚洲季风气候区（东亚、东南亚、南亚）。'},
  {c:'气候',q:'地中海气候区（如南欧）最适合种植的农作物是？',o:['水稻','小麦和玉米（雨热同期）','油橄榄、葡萄、柑橘等（耐旱耐热）','棉花'],a:2,e:'地中海气候：夏干热、冬温湿（雨热不同期）。当地农业适应气候，种植耐旱的油橄榄、葡萄、柑橘、无花果等，冬季种小麦。"雨热不同期"是与季风气候的重要区别。'},
  {c:'气候',q:'全球气候变暖的主要原因是？',o:['太阳活动增强','大量燃烧化石燃料（煤油气）导致CO₂等温室气体增多','核电站增多','人口增多'],a:1,e:'全球变暖：大量燃烧化石燃料+森林砍伐→大气中CO₂、甲烷等温室气体浓度升高→温室效应增强→全球升温。影响：极冰融化、海平面上升、极端气候增多。'},
  {c:'气候',q:'下列属于气候对人类生产的有利影响的是？',o:['洪涝灾害破坏农业','中国东部季风气候雨热同期，有利于农业生产','干旱导致减产','霜冻导致农作物死亡'],a:1,e:'中国东部季风气候：夏季高温多雨（雨热同期），与农作物生长季节吻合，有利于水稻、玉米等作物生长。这是季风气候对农业最重要的有利影响。'}
);

/* ── 七上·第五章·第一节 人口与人种（补充 +10） ── */
window.QB_G7_C5_S1.push(
  {c:'人口',q:'人口自然增长率=出生率-死亡率，若某地出生率1.2%、死亡率0.7%，自然增长率是？',o:['1.9%','0.5%','0.7%','1.2%'],a:1,e:'人口自然增长率=出生率-死亡率=1.2%-0.7%=0.5%。人口自然增长率>0，人口增加；<0，人口减少（负增长）；=0，零增长。'},
  {c:'人口',q:'人口密度的计算公式是？',o:['人口总数×面积','人口总数÷面积（人/平方千米）','面积÷人口总数','出生率-死亡率'],a:1,e:'人口密度=人口总数÷面积，单位：人/平方千米。人口密度反映人口分布的疏密程度。'},
  {c:'人口',q:'世界人口超过10亿的国家（人口大国）是？',o:['中国和美国','中国和印度（均超14亿）','印度和俄罗斯','美国和巴西'],a:1,e:'2023年，印度超越中国成为世界第一人口大国（约14.29亿）。中国约14.09亿，两国均超14亿，远超其他国家。'},
  {c:'人口',q:'欧洲一些国家人口自然增长率出现负值，带来的社会问题是？',o:['人口太多资源短缺','人口老龄化严重，劳动力不足，社保压力大','教育资源不足','粮食短缺'],a:1,e:'人口负增长（多出现在发达国家）：出生率低、老龄化严重→劳动力不足→经济活力下降→社会保障（养老金、医疗）压力增大，这是欧洲、日本等国的人口问题。'},
  {c:'人口',q:'世界人口分布稀疏的原因，以下说法正确的是？',o:['只有气候原因','自然条件恶劣（极寒、极旱、高原等）和社会经济因素共同影响','只有战争原因','只有交通原因'],a:1,e:'人口稀疏地区的原因：①自然：过于干旱（沙漠）、过于寒冷（极地、高山）、过于湿热（热带雨林）②社会：战争、经济落后、交通不便等。'},
  {c:'人口',q:'黑色人种（尼格罗人种）的主要特征是？',o:['皮肤白皙，发色较浅','皮肤黝黑，头发卷曲，鼻宽唇厚','皮肤黄色，头发黑色直发','皮肤红铜色'],a:1,e:'黑色人种主要特征：皮肤黝黑（黑色素多）、头发卷曲、鼻较宽、嘴唇较厚，主要分布在撒哈拉以南非洲，以及美洲（由历史上的奴隶贸易迁移）。'},
  {c:'人口',q:'黄色人种（蒙古人种）主要分布在？',o:['欧洲','西亚北非','东亚（中国、日本、韩国）和东南亚，以及美洲原住民','撒哈拉以南非洲'],a:2,e:'黄色人种主要分布在：东亚（中日韩）、东南亚（部分）、中亚，以及北美和南美洲的印第安人（原住民）也属蒙古人种。'},
  {c:'人口',q:'人种的形成主要是由于长期？',o:['战争导致','在不同自然环境（气候、地形等）中，人体适应环境的自然选择','宗教差异','文化不同'],a:1,e:'人种差异（肤色、发型等）是人类祖先在不同自然环境中长期演化（自然选择）的结果。如热带地区黑皮肤能抵御紫外线，寒带地区白皮肤利于在弱光中合成维生素D。人种无优劣之分。'},
  {c:'人口',q:'以下哪个洲人口自然增长率最低（接近或为负增长）？',o:['非洲','亚洲','欧洲（部分国家负增长）','北美洲'],a:2,e:'欧洲人口自然增长率最低，多国（德国、意大利、俄罗斯等）出现负增长，老龄化严重，年轻劳动力不足，需引进移民。'},
  {c:'人口',q:'城市化过度（过快）带来的问题包括？',o:['农村人口增多','交通拥堵、住房紧张、环境污染、贫民窟等城市病','粮食产量增加','资源更加充足'],a:1,e:'城市化过快（尤其是发展中国家）："城市病"——交通拥堵、住房紧张、就业困难、贫民窟增多、环境污染、犯罪率上升等。发达国家已出现"逆城市化"（人口向郊区、农村回迁）。'}
);

/* ── 七上·第五章·第二节 城镇与乡村（补充 +11） ── */
window.QB_G7_C5_S2.push(
  {c:'人口',q:'与乡村聚落相比，城市聚落（城市）的特征是？',o:['以农业为主，人口稀少','以工商业、服务业为主，人口密集，设施完善，建筑密集','以牧业为主','靠近自然环境，道路少'],a:1,e:'城市特征：①以工商业、服务业为主②人口密集（人口密度大）③基础设施完善（学校、医院、交通）④建筑密集高层多。乡村以农业生产为主，布局分散，设施相对简单。'},
  {c:'人口',q:'以下哪种地区不利于聚落的形成？',o:['河流沿岸的冲积平原','气候温暖湿润的丘陵','水源充足的绿洲','地震频繁的断层带或泥石流频发区'],a:3,e:'自然灾害频发的地区（地震断层、泥石流、洪泛区、滑坡）不适合建立聚落，安全是聚落选址的首要考虑。'},
  {c:'人口',q:'世界上最大的城市群（特大都市圈）在哪里？',o:['伦敦都市圈','巴黎都市圈','东京大都市圈（约3700万人）','纽约都市圈'],a:2,e:'东京大都市圈（包括东京、横滨、千叶、埼玉等）人口约3700万，是全球人口最多的都市圈，也是世界重要金融中心。'},
  {c:'人口',q:'\"古代聚落多选在河流弯曲处\"的原因是？',o:['河流弯曲处水流快','弯曲处水面宽，具有三面环水的天然防御优势，且靠近水源、土地肥沃','弯曲处便于捕鱼','弯曲处气候更好'],a:1,e:'古代聚落选择河流弯曲（凸岸）处：①三面环水，易于防御②水源充足③河流弯曲处堆积，土地肥沃④渡河方便。这是古代城市选址的重要原则（如北京选于永定河冲积扇上）。'},
  {c:'人口',q:'随着城镇化发展，乡村人口向城市迁移，乡村面临的问题是？',o:['乡村设施更加完善','农村劳动力减少、老龄化、村庄空心化（留守儿童和老人问题）','农村经济发展更快','乡村人口增多'],a:1,e:'城镇化导致农村大量青壮年外出务工，农村出现：劳动力短缺、土地抛荒、老龄化严重、留守儿童问题、村庄"空心化"等问题。'},
  {c:'人口',q:'聚落的建筑风格与自然环境关系密切，"蒙古包（圆顶毡房）"的建筑特点适应的是？',o:['高温多雨的热带环境','草原游牧生活（便于拆装迁移）和大风天气（圆顶抗风）','寒冷多雪的高山环境','多雨的沿海环境'],a:1,e:'蒙古包适应内蒙古草原游牧生活：①圆形可拆卸，便于随牧群迁徙②圆顶抗风③保暖性好（毡布隔热保温）。建筑风格是人类适应自然环境的智慧结晶。'},
  {c:'人口',q:'西双版纳傣族竹楼底层架空，主要是为了？',o:['美观','便于通风防潮（热带雨林气候湿热），也能防野兽','储存物品','省材料'],a:1,e:'竹楼（干栏式建筑）底层架空：①通风散热，防潮湿（热带多雨）②防野兽侵扰③防洪水。这是热带雨林地区建筑适应湿热气候的典型案例。'},
  {c:'人口',q:'北非、西亚的平顶房屋最适合的气候是？',o:['温带海洋性气候（多雨）','热带雨林气候','热带沙漠气候（干旱少雨，平顶可作晒台）','寒带气候'],a:2,e:'北非、西亚热带沙漠气候降水极少，无需坡屋顶排雨。平顶房屋：①建材省②屋顶可用作晒台或纳凉场所③墙厚窗小保持室内凉爽，是干旱地区的传统民居特点。'},
  {c:'人口',q:'随着科技发展，影响聚落形成的主导因素已从自然条件转变为？',o:['自然条件依然是唯一因素','自然条件完全不重要','社会经济因素（交通、政策、科技）越来越重要','宗教因素'],a:2,e:'现代社会，交通（高铁站、港口）、政策（开发区）、科技（工业园区）等社会经济因素对聚落形成的影响越来越大，自然条件的制约相对减弱（如沙漠城市拉斯维加斯、迪拜）。'},
  {c:'人口',q:'下列城市中，因港口兴起发展的是？',o:['兰州（内陆交通枢纽）','上海（长江入海口，河海联运枢纽）','乌鲁木齐','拉萨'],a:1,e:'上海位于长江入海口，是中国最大港口城市，因海上贸易和河运便利而繁荣。许多世界大城市都是靠港口兴起的，如伦敦（泰晤士河口）、纽约（哈德逊河口）、新加坡（马六甲海峡旁）。'},
  {c:'人口',q:'乡村聚落与城市聚落的根本区别在于？',o:['人口多少','建筑高低','人口从事的产业类型（农业vs工商业）和生活方式','道路宽窄'],a:2,e:'城乡最根本区别：乡村居民主要从事农业生产（种植业、畜牧业、渔业等），城市居民主要从事工业和商业服务业。这决定了两者在人口密度、建筑、设施等方面的一系列差异。'}
);

/* ── 七上·第五章·第三节 多样的文化（补充 +11） ── */
window.QB_G7_C5_S3.push(
  {c:'人口',q:'基督教的圣地和总部在哪里？',o:['麦加（沙特阿拉伯）','耶路撒冷（以色列）和梵蒂冈（意大利）','拉萨（中国西藏）','德里（印度）'],a:1,e:'基督教圣地：耶路撒冷（耶稣传道受难之地）；天主教总部：梵蒂冈（意大利）。伊斯兰教圣地：麦加（沙特）。佛教圣地：菩提伽耶（印度）。'},
  {c:'人口',q:'印度教主要分布在哪里？',o:['东南亚','中东地区','印度及尼泊尔','西非'],a:2,e:'印度教是印度的主要宗教（约80%人口信仰），也在尼泊尔广泛分布，主要流行于南亚地区，信仰者约11亿，是世界第三大宗教（若计入）。'},
  {c:'人口',q:'下列关于语言的说法，正确的是？',o:['英语是使用人数最多的语言','汉语是世界通用语（联合国工作语言之一），使用人数最多','阿拉伯语只在沙特阿拉伯使用','西班牙语仅在西班牙使用'],a:1,e:'汉语（普通话）母语使用人数约14亿，是使用人数最多的语言。英语是最广泛的国际通用语。联合国6种官方语言：阿拉伯、中、英、法、俄、西班牙语。'},
  {c:'人口',q:'阿拉伯语主要分布在哪个地区？',o:['东南亚','西非和东非','西亚和北非（中东和北非地区）','南亚'],a:2,e:'阿拉伯语是西亚和北非22个阿拉伯国家的官方语言，使用人口约4亿，与伊斯兰教密切相关（《古兰经》用阿拉伯语书写）。'},
  {c:'人口',q:'下列属于文化差异的体现是？',o:['不同地区气温不同','不同地区降水不同','各地饮食、服装、建筑、风俗习惯各不相同','不同地区地形各异'],a:2,e:'文化是人类在社会发展中创造的物质和精神财富，包括语言、宗教、饮食习惯、建筑风格、服装、礼仪等。这些差异体现了文化的多样性。'},
  {c:'人口',q:'佛教起源于？',o:['中国','古印度（公元前5世纪，创始人释迦牟尼）','日本','东南亚'],a:1,e:'佛教起源于古印度（约公元前5世纪），创始人释迦牟尼（乔达摩·悉达多），后传入中国、东南亚、日本、韩国等亚洲各地，现信众约5亿，主要分布在亚洲东部和东南部。'},
  {c:'人口',q:'伊斯兰教徒（穆斯林）有哪些宗教习俗？',o:['每天祷告一次，忌酒忌猪肉，朝向麦加礼拜，斋月期间白天禁食','每天祷告七次，可以喝酒','没有饮食禁忌','主要在亚洲东部'],a:0,e:'伊斯兰教主要习俗：①每天5次礼拜（朝向麦加）②斋月（拉马丹）白天禁食③禁酒、禁食猪肉④一生至少到麦加朝圣一次（朝觐）。这些是伊斯兰五功的重要内容。'},
  {c:'人口',q:'文化多样性的意义是？',o:['文化差异会导致冲突，应统一为一种文化','文化多样性是人类的共同财富，应相互尊重、理解和保护','各种文化有优劣之分','应只保留最古老的文化'],a:1,e:'文化多样性是人类文明的宝贵财富，不同文化各有其价值。正确态度：尊重文化差异、平等相待、取长补短、保护濒危文化（如非物质文化遗产保护）。'},
  {c:'人口',q:'非洲有丰富的语言文化，使用语言数量约为？',o:['50种','200种','2000种以上','5种'],a:2,e:'非洲是语言最多样的大洲，有2000种以上的语言，平均每个国家有数十种语言。殖民历史使英语、法语、葡萄牙语成为许多非洲国家的官方语言，同时本土语言（如斯瓦希里语）也广泛使用。'},
  {c:'人口',q:'中国的主要宗教有哪些？',o:['只有佛教','只有道教','佛教、道教、伊斯兰教、基督教、天主教（五大宗教）','只有儒教'],a:2,e:'中国有五大官方认可的宗教：佛教（信众最多）、道教（中国本土宗教）、伊斯兰教（回族等少数民族）、基督教、天主教。中国是多宗教共存的国家，宗教政策是信仰自由。'},
  {c:'人口',q:'\"饮食文化\"受地理环境影响，以下搭配正确的是？',o:['南方（华南）以面食（小麦）为主','北方（华北）以米饭（水稻）为主','南稻北麦——南方以水稻（米饭）为主，北方以小麦（面食）为主','东西方饮食完全相同'],a:2,e:'"南稻北麦"：中国南方气候湿热，适合水稻生长，以米饭为主食；北方气候较干，适合小麦生长，以面食（馒头、面条）为主。饮食习惯深受当地农业生产（气候、地形）影响。'}
);

/* ── 七上·第六章 发展与合作（补充 +10） ── */
window.QB_G7_C6.push(
  {c:'经济',q:'发展中国家与发达国家的主要区别是？',o:['人口多少','面积大小','经济发展水平（人均GDP、工业化程度、社会福利等）','地理位置'],a:2,e:'发达国家vs发展中国家主要区别：经济总量、人均GDP、工业化水平、科技水平、社会福利等。发达国家人均GDP高、社会保障完善；发展中国家正处于工业化、现代化进程中。'},
  {c:'经济',q:'中国属于哪类国家？',o:['发达国家','发展中国家（最大的发展中国家）','两者之间的中等国家','无法分类'],a:1,e:'中国是世界上最大的发展中国家，GDP总量居世界第二，但人均GDP仍低于发达国家水平，正处于快速发展阶段，是发展中国家的代表和领导者。'},
  {c:'经济',q:'国际贸易中，发展中国家主要出口什么，进口什么？',o:['出口高科技产品，进口原材料','出口工农业原材料（初级产品），进口工业制成品','出口和进口完全平衡','出口服务，进口农产品'],a:1,e:'国际贸易不平等：发展中国家多出口农矿原材料（价格低），进口工业制成品和技术（价格高），这种不平等的贸易关系限制了发展中国家经济发展。'},
  {c:'经济',q:'世界贸易组织（WTO）的主要职能是？',o:['政治安全','促进国际自由贸易，制定贸易规则，解决贸易争端','军事防御','文化交流'],a:1,e:'世贸组织（WTO）成立于1995年，总部日内瓦，主要职能：①制定国际贸易规则②促进自由贸易（降低关税壁垒）③解决成员国贸易争端。中国2001年加入WTO。'},
  {c:'经济',q:'非政府组织（NGO）在国际发展合作中发挥的作用是？',o:['与政府一样拥有执法权','通过募款、志愿者等方式，在人道主义、环境、扶贫等领域补充政府力量','只在本国活动','没有实际作用'],a:1,e:'非政府组织（如红十字会、绿色和平、无国界医生）：独立于政府，在医疗救援、环境保护、扶贫发展等领域发挥重要补充作用，是国际合作的重要力量。'},
  {c:'经济',q:'\"一带一路\"倡议（丝绸之路经济带和21世纪海上丝绸之路）由哪个国家提出？',o:['美国','俄罗斯','中国（2013年提出）','欧盟'],a:2,e:'"一带一路"由中国国家主席习近平于2013年提出，旨在促进亚欧非基础设施互联互通和经济合作，是推动全球化和南南合作的重要举措。'},
  {c:'经济',q:'以下属于世界主要国际组织的是？',o:['只有联合国','联合国、世贸组织、世界银行、国际货币基金组织（IMF）、世界卫生组织（WHO）等','只有北约','只有亚太经合组织'],a:1,e:'主要国际组织：①政治安全：联合国（最大最权威）②经济：WTO、IMF、世界银行③卫生：WHO④区域合作：欧盟、ASEAN、APEC等。国际组织是国际合作的重要平台。'},
  {c:'经济',q:'发展中国家发展经济面临的最主要挑战是？',o:['人口太少','资金不足、技术落后、基础设施薄弱、不平等的国际经济秩序等','人口太多（实际上劳动力是优势）','气候太差'],a:1,e:'发展中国家面临：①资金短缺（外债多）②技术落后③人才不足④基础设施薄弱⑤受不公平国际贸易体系制约⑥历史殖民遗留问题。但劳动力资源丰富是相对优势。'},
  {c:'经济',q:'欧盟是哪类国际合作组织？',o:['军事联盟','纯经济组织','区域一体化组织（经济政治一体）','联合国下属机构'],a:2,e:'欧盟（EU）成立于1993年（前身欧共体），是世界上一体化程度最高的区域组织，成员国实现了单一市场（商品、人员、服务、资本自由流动）和统一货币（欧元）。'},
  {c:'经济',q:'\"援助\"和\"合作\"的区别是？',o:['两者完全相同','援助是单向给予，合作是双方互惠互利、共同发展','合作是援助的一种形式','援助比合作更重要'],a:1,e:'国际关系中：援助（单向）=发达国家向发展中国家提供资金、技术、物资等；合作（双向）=双方基于平等互惠共同发展（如"南南合作"是发展中国家间平等合作）。'}
);

