window.QB_G7_C7_S1.push(
  {c:'地形',q:'亚洲地形以什么为主？',o:['以平原为主，地势低平','以山地、高原为主（占亚洲总面积约75%），地势中高四周低','以丘陵为主','以盆地为主'],a:1,e:'亚洲地形复杂多样，山地、高原、丘陵约占总面积75%，平原面积相对较小。中部有青藏高原（"世界屋脊"）、帕米尔高原，四周有大平原（华北、西西伯利亚、印度河恒河平原）。'},
  {c:'地形',q:'发源于青藏高原的世界著名大河包括？',o:['亚马逊河、刚果河','长江、黄河、湄公河、印度河、恒河等','多瑙河、莱茵河','密西西比河、科罗拉多河'],a:1,e:'青藏高原是"亚洲水塔"，发源于此的大河：长江（入东海）、黄河（入渤海）、湄公河（入南海）、萨尔温江、伊洛瓦底江（入印度洋）、印度河、恒河（入阿拉伯海）等。'},
  {c:'地形',q:'亚洲气候类型种类为什么比其他大洲多？',o:['亚洲人口多','亚洲纬度跨度大（跨寒温热三带）、面积广、海陆关系复杂、地形多样','亚洲海拔高','亚洲靠近赤道'],a:1,e:'亚洲气候类型最多样：①跨越寒、温、热三带（南北跨约70°纬度）②东西距离广（海陆差异显著）③地形复杂多样（青藏高原产生高原气候）。几乎包含地球上所有气候类型。'},
  {c:'地形',q:'亚洲季风气候中，东亚季风的冬夏季风来源分别是？',o:['冬季来自海洋，夏季来自内陆','冬季来自亚洲大陆内部（干冷），夏季来自太平洋（湿热）','全年都来自海洋','全年都来自内陆'],a:1,e:'东亚季风：①冬季风：亚洲大陆高压→偏北（西北）风，寒冷干燥②夏季风：太平洋副高→偏南（东南）风，温暖湿润。季风气候特点：夏热多雨，冬冷少雨。'},
  {c:'地形',q:'亚洲内陆的温带大陆性气候，降水量少的原因是？',o:['纬度太高','距海遥远，水汽难以到达，蒸发旺盛','地形影响','洋流影响'],a:1,e:'温带大陆性气候（亚洲内陆如中亚、中国西北）距海遥远，湿润海洋气流难以深入，降水量少（年均<400mm甚至<200mm），气温年较差大（冬冷夏热）。'},
  {c:'地形',q:'亚洲面积最大的地形区是？',o:['华北平原','西西伯利亚平原','青藏高原（约250万平方千米）','西伯利亚山地'],a:1,e:'西西伯利亚平原面积约290万平方千米，是亚洲（也是世界）面积最大的平原之一；青藏高原约250万平方千米，是世界面积最大的高原。'},
  {c:'地形',q:'亚洲与北美洲的分界海峡是？',o:['马六甲海峡','霍尔木兹海峡','白令海峡（连接太平洋和北冰洋）','英吉利海峡'],a:2,e:'白令海峡：宽约85km，连通太平洋（白令海）和北冰洋，是亚洲（俄罗斯远东）与北美洲（美国阿拉斯加）的分界线，最近处约4km（可在冰期步行渡越）。'},
  {c:'地形',q:'亚洲有极地气候的原因是？',o:['亚洲靠近赤道','亚洲北部（西伯利亚、俄罗斯北极区）延伸至北极圈甚至北极圈以内','亚洲海拔太高','亚洲降水太少'],a:1,e:'亚洲北端（俄罗斯西伯利亚北部）延伸至北冰洋沿岸，纬度极高（北极圈66.5°N以内），形成极地气候（苔原气候和冰原气候）。'},
  {c:'地形',q:'亚洲最长的河流长江，流向是？',o:['自北向南','自西向东（发源青藏高原，向东流入东海）','自东向西','自南向北'],a:1,e:'长江发源于青藏高原（唐古拉山脉），自西向东横穿中国中部，全长约6300km，流经11个省市，在上海入东海，是亚洲最长的河流和中国第一大河。'}
);

/* ── 七下·第七章·第二节 亚洲人文环境（补充 +11） ── */
window.QB_G7_C7_S2.push(
  {c:'人口',q:'亚洲人口约占世界总人口多少？',o:['约30%','约50%','约60%以上（超过46亿）','约80%'],a:2,e:'亚洲是世界上人口最多的大洲，约占全球总人口的60%以上（超过46亿），拥有中国、印度两个超级人口大国。'},
  {c:'人口',q:'亚洲人口稀少的地区是？',o:['东亚东部','南亚印度半岛','亚洲中部（中亚内陆）和西伯利亚北部，沙漠高原区','东南亚沿海'],a:2,e:'亚洲人口稀少地区：①中亚内陆（沙漠、干旱）②西伯利亚（寒冷）③青藏高原（高寒）④阿拉伯半岛沙漠。人口集中在东亚、东南亚、南亚。'},
  {c:'人口',q:'亚洲经济发展水平差异大，其中经济最发达的国家（传统发达国家）是？',o:['中国','印度','日本','韩国'],a:2,e:'日本是亚洲唯一的传统发达国家，人均GDP在亚洲最高（约3万美元以上），是全球第三大经济体，以高科技制造业和服务业为主。韩国、新加坡、以色列是亚洲新发达国家。'},
  {c:'人口',q:'中东（西亚）的波斯湾产油国（如沙特、阿联酋）人均GDP高，但人口构成特殊，原因是？',o:['本国人口多','主要靠旅游业','石油出口致富但本国人口少，大量引进外籍劳工（外籍工人占60-90%）','农业发达'],a:2,e:'海湾产油国（沙特、阿联酋、卡塔尔等）：石油资源丰富，人均GDP极高；但本国人口少，劳动力不足，大量引进南亚（印度、巴基斯坦、孟加拉）外籍劳工从事基础设施建设和服务业。'},
  {c:'人口',q:'亚洲文化的多样性主要体现在？',o:['所有亚洲国家文化完全相同','宗教、语言、民族、传统习俗等方面的巨大差异（世界三大宗教均发源于亚洲西部）','只有语言差异','只有宗教差异'],a:1,e:'亚洲文化极其多样：①宗教：佛教（南亚东南亚）、伊斯兰教（西亚南亚）、印度教（印度）、儒家文化（东亚）②语言：数百种③民族：数千个④传统节日、饮食、建筑各异。'},
  {c:'人口',q:'亚洲农业类型多样，东亚东南亚南亚的主要农业类型是？',o:['牧场畜牧业','水田农业（季风水田农业，以水稻为主）','旱地农业','游牧业'],a:1,e:'东亚（中日韩）、东南亚、南亚（印度）：季风气候，高温多雨，以水稻种植（水田农业）为主，是世界水稻主产区。中亚内陆：干旱，以畜牧业和旱地农业（小麦）为主。'},
  {c:'人口',q:'亚洲西部（西亚）的产业结构主要依赖？',o:['制造业','农业（小麦种植）','石油工业和石化产业','旅游业'],a:2,e:'西亚（中东）产业结构以石油为支柱，石油出口是主要外汇来源。近年来（阿联酋、沙特等）在推动经济多元化，发展旅游（迪拜）、金融、制造业，减少对石油单一依赖。'},
  {c:'人口',q:'亚洲面临的共同发展问题包括？',o:['人口过少','环境污染与生态破坏、贫富分化（国家间和国家内部）、部分地区政局不稳等','粮食产量过剩','水资源过多'],a:1,e:'亚洲发展问题：①环境污染（工业化进程中）②贫富分化（发达日本VS贫穷国家差距大）③人口压力（南亚）④政治不稳（中东）⑤水资源争端（跨境河流）等。'},
  {c:'人口',q:'新加坡是亚洲著名的城市国家，其经济发展依靠的主要是？',o:['丰富的自然资源','人力资源、地理位置（马六甲海峡旁）和完善的法治环境','大量农业用地','廉价劳动力'],a:1,e:'新加坡自然资源极度匮乏（土地面积仅728km²，无农业，依赖进口粮食和水），但凭借马六甲海峡的地理优势、高素质人力资源、法治透明的营商环境，发展为全球重要金融、航运、科技中心。'},
  {c:'人口',q:'亚洲的"四小龙"（韩国、新加坡、台湾、香港）经济腾飞的共同模式是？',o:['依赖丰富自然资源出口','利用劳动力优势发展出口导向型制造业，后升级高科技和服务业','依赖农业','靠旅游业'],a:1,e:'"亚洲四小龙"：20世纪60-80年代，依靠廉价劳动力吸引外资，发展劳动密集型出口制造业起步，积累资本后逐步升级到技术密集型和服务业，成为新兴经济体。'},
  {c:'人口',q:'亚洲人口最多的国家依次是？',o:['中国、印度、日本','印度、中国、孟加拉国','中国、印度、印度尼西亚','印度、中国、巴基斯坦'],a:2,e:'2024年亚洲人口最多：①印度（约14.4亿，2023年超中国）②中国（约14.1亿）③印度尼西亚（约2.8亿）④巴基斯坦（约2.3亿）⑤孟加拉国（约1.7亿）。'}
);

/* ── 七下·第八章·第一节 日本（补充 +9） ── */
window.QB_G7_C8_S1.push(
  {c:'地形',q:'日本四大岛由北到南依次是？',o:['九州、四国、本州、北海道','北海道、本州、四国、九州','本州、北海道、四国、九州','本州、九州、四国、北海道'],a:1,e:'日本四大岛（从北到南）：北海道→本州（最大，东京、大阪等主要城市）→四国→九州。四大岛加约6800个小岛，构成日本全部国土。'},
  {c:'地形',q:'日本经济的核心优势是？',o:['矿产资源丰富','人口众多劳动力廉价','科技水平高、加工贸易型经济、产品质量好','农业发达粮食充足'],a:2,e:'日本经济特点：资源匮乏→发展加工贸易（大量进口原料→加工为高附加值产品出口）；科技水平高（汽车、电子、精密仪器、机器人等领域世界领先）；劳动力素质高。'},
  {c:'地形',q:'日本"太平洋工业带"从东北到西南，主要包括哪些工业区？',o:['札幌、仙台、东京','东京湾（首都圈）、名古屋、大阪神户、北九州（北部九州）','大阪、福冈、那霸','青森、秋田、新潟'],a:1,e:'日本太平洋沿岸工业带（从东北到西南）：东京湾工业区（最大）→名古屋工业区（汽车中心）→阪神工业区（大阪神户）→濑户内海工业区→北九州工业区。'},
  {c:'地形',q:'日本海洋性季风气候的特点是？',o:['全年干旱','冬季严寒漫长，夏季炎热短暂','温和湿润，四季分明，降水丰富','全年高温多雨'],a:2,e:'日本属温带（北部）和亚热带（南部）季风气候，受海洋影响较大：温和湿润，冬季较中国同纬度暖（暖流影响），多梅雨（6月）和台风（8-9月），年降水量丰富（1000-2000mm以上）。'},
  {c:'地形',q:'日本人均GDP高，但贫富分化问题相对较小，主要原因是？',o:['日本自然资源丰富','完善的社会福利体系和较均衡的收入分配','人口少','地形以平原为主'],a:1,e:'日本贫富差距相对较小（基尼系数较低）：完善的社会保障体系（全民医保、国民年金）、相对均等的教育机会、较完善的劳动法保护。这是日本社会稳定的重要基础。'},
  {c:'地形',q:'日本对中国文化的历史借鉴主要发生在？',o:['唐代（奈良时代到平安时代）是高峰期','现代只有商贸','只有文字','完全没有借鉴'],a:0,e:'历史上日本大量借鉴中国文化：汉字（演变为假名）、儒学、佛教（经朝鲜传入）、唐代建筑（奈良大佛、平城京仿长安）、律令制度等。"遣唐使"制度（630-894年）是重要渠道。'},
  {c:'地形',q:'日本富士山是哪种地形？',o:['侵蚀形成的山地','板块碰撞形成的褶皱山','活火山（至今仍可能喷发）','死火山（已经停止活动）'],a:2,e:'富士山（3776m）是日本最高峰，位于本州，是典型的圆锥形层状火山（复式火山），最后一次喷发于1707年，现被认定为"休眠火山"（可能再次喷发）。'},
  {c:'地形',q:'日本料理（和食）在2013年被列入联合国教科文组织非物质文化遗产，这说明？',o:['日本料理是最好吃的料理','文化多样性值得保护和传承','日本是世界最强国','料理没有营养价值'],a:1,e:'和食被列入非遗，体现了联合国教科文组织对文化多样性的重视——各国传统饮食文化是人类非物质文化遗产的重要组成部分，值得保护和传承。'},
  {c:'地形',q:'日本"泡沫经济"崩溃（1990年代初）后，经济长期低迷的根本原因是？',o:['战争影响','人口老龄化加剧、内需不足、产业升级困难、政策失误等综合因素','资源枯竭','自然灾害频繁'],a:1,e:'日本"失去的三十年"：①人口老龄化严重（内需不足）②通货紧缩恶性循环③制造业向海外转移（空心化）④政策应对迟缓⑤企业创新不足。这是当前日本经济的主要困境。'}
);

/* ── 七下·第八章·第二节 东南亚（补充 +10） ── */
window.QB_G7_C8_S2.push(
  {c:'地形',q:'东南亚的战略地理位置（"十字路口"）体现在？',o:['东南亚距离中国很近','马六甲海峡是太平洋和印度洋之间的重要航运通道，是"海上丝绸之路"要冲','东南亚气候适宜','东南亚人口多'],a:1,e:'东南亚地处亚欧大陆和澳大利亚之间、太平洋和印度洋之间的"十字路口"。马六甲海峡是中东石油运往日本、中国的必经之路，是全球最重要的海运通道之一（"海上生命线"）。'},
  {c:'地形',q:'东南亚最重要的稻米出口国是？',o:['印度尼西亚','菲律宾','泰国（世界重要大米出口国）','马来西亚'],a:2,e:'泰国、越南是东南亚最重要的水稻出口国，泰国大米以香米（茉莉香米）闻名全球。中南半岛河流中下游（湄公河、湄南河三角洲）土地肥沃，是重要水稻产区。'},
  {c:'地形',q:'马六甲海峡连通了哪两大洋？',o:['大西洋和太平洋','太平洋和印度洋（马来半岛和苏门答腊岛之间）','太平洋和北冰洋','大西洋和印度洋'],a:1,e:'马六甲海峡（位于马来半岛与印尼苏门答腊岛之间）是太平洋和印度洋之间最重要的水道，长约1000km，最窄处约37km，每年通过船只超8万艘。'},
  {c:'地形',q:'东南亚各国的宗教分布规律是？',o:['全部信伊斯兰教','全部信佛教','地区差异大：中南半岛以佛教为主，印度尼西亚马来西亚以伊斯兰教为主，菲律宾以天主教为主','全部信基督教'],a:2,e:'东南亚宗教多样：①中南半岛（泰国、缅甸、老挝、柬埔寨等）以佛教（上座部佛教）为主②马来西亚、文莱、印尼以伊斯兰教为主③菲律宾（西班牙殖民遗留）以天主教为主。'},
  {c:'地形',q:'东南亚的"香料群岛"历史上指的是？',o:['菲律宾','越南','马鲁古群岛（印度尼西亚）——丁香、肉豆蔻等香料原产地','新加坡'],a:2,e:'马鲁古群岛（摩鹿加群岛）历史上是全球丁香、肉豆蔻等香料的唯一产地，曾引发欧洲列强争夺，是"地理大发现"时代重要的航海目标，今属印度尼西亚。'},
  {c:'地形',q:'新加坡经济高度发达，其主要支柱产业是？',o:['农业和矿业','制造业（石化、电子）、金融、贸易、旅游和港口服务','渔业','林业'],a:1,e:'新加坡主要支柱产业：①港口与航运（世界最繁忙港口之一）②金融（亚洲重要金融中心）③石化（裕廊岛）④电子制造⑤旅游（圣淘沙、滨海湾花园）。无农业，基本依赖进口。'},
  {c:'地形',q:'越南的"革新开放"（Doi Moi，1986年）使越南经济快速发展，类似于中国的？',o:['文化大革命','改革开放（1978年）','大跃进','五四运动'],a:1,e:'越南"革新开放"（Doi Moi，1986年）：引入市场经济机制，吸引外资，发展出口加工业，经济持续快速增长。与中国1978年改革开放的路径相似，均为"社会主义市场经济"模式。'},
  {c:'地形',q:'东南亚热带雨林大量砍伐的主要原因是？',o:['气候变化导致树木自然死亡','人口增长带来的农业开荒、棕榈油种植园扩张和木材出口需求','病虫害','自然火灾'],a:1,e:'东南亚雨林破坏：①棕榈油种植（印尼、马来西亚大量毁林种棕榈）②农业开荒（人口增长）③木材出口④采矿。棕榈油产业是主要驱动力，印尼毁林率全球最高之一。'},
  {c:'地形',q:'东南亚"中南半岛"的地形特征是？',o:['一望无际的平原','山脉与河流并排分布（山河相间，南北纵列）','只有高原','以盆地为主'],a:1,e:'中南半岛地形：山脉和河流南北纵向排列（"山河相间，南北纵列"）——科罗曼德尔山、湄南河、他念他翁山、萨尔温江、翁山山脉、伊洛瓦底江等平行分布，使得各流域相对独立。'},
  {c:'地形',q:'东南亚出产的哪种农产品是全球最重要的食用油来源之一？',o:['椰子油','棕榈油（印尼、马来西亚占全球产量约85%）','花生油','大豆油'],a:1,e:'棕榈油：印度尼西亚和马来西亚是全球最大的棕榈油生产国（共占约85%），广泛用于食品加工、化妆品、生物柴油。棕榈油是全球产量最大的植物油，但其种植引发了严重的雨林砍伐问题。'}
);

/* ── 七下·第八章·第三节 印度（补充 +10） ── */
window.QB_G7_C8_S3.push(
  {c:'地形',q:'印度主要地形单元从北到南是？',o:['沿海平原→中央高原→喜马拉雅山','喜马拉雅山（北部）→恒河平原（中部）→德干高原（南部）','德干高原→恒河平原→喜马拉雅山','平原→山地→高原'],a:1,e:'印度地形三部分：①北部：喜马拉雅山脉（山地）②中部：恒河—印度河平原（世界上最大的冲积平原之一，人口密集，农业发达）③南部：德干高原（古老地盾，矿产丰富）。'},
  {c:'地形',q:'印度的"绿色革命"（20世纪60-70年代）主要是指？',o:['推广种植蔬菜','引进高产种子、化肥、灌溉技术，大幅提高粮食产量','大规模植树造林','改善城市绿化'],a:1,e:'绿色革命：在发展中国家推广高产粮食品种（矮秆小麦、水稻）配合化肥、农药、灌溉，大幅提高产量。印度通过绿色革命基本实现粮食自给（1970年代后），结束了长期依赖进口粮食的局面。'},
  {c:'地形',q:'印度班加罗尔被称为"印度硅谷"，主要原因是？',o:['班加罗尔人口最多','班加罗尔有丰富的矿产资源','班加罗尔聚集了大量IT（软件）企业和工程师（英语优势+理工科人才多）','班加罗尔气候最好'],a:2,e:'班加罗尔IT产业发达：①英国殖民历史→高水平英语教育②理工科（IIT等顶级院校）培养大量IT人才③劳动力成本低于欧美④政策扶持。许多欧美IT巨头（微软、IBM、谷歌等）在此设有研发中心。'},
  {c:'地形',q:'印度种姓制度对社会的影响是？',o:['有利于社会公平','按出生划分社会等级（婆罗门→刹帝利→吠舍→首陀罗），限制社会流动，加剧不平等','对社会没有影响','已完全废除'],a:1,e:'种姓制度（印度教传统）按出生决定社会等级，影响就业、婚姻、社会交往。印度独立后宪法废除种姓制度，但其影响在农村依然深刻，是印度社会不平等和歧视（尤其是"不可接触者"达利特）的重要根源。'},
  {c:'地形',q:'恒河对印度的重要意义是？',o:['提供大量矿产资源','是印度最重要的农业水源和印度教圣河，孕育古印度文明','只有宗教意义','只有交通意义'],a:1,e:'恒河（约2510km）：①农业：流域是印度最重要的农业区（小麦、水稻）②文化：印度教最神圣的河流（"母亲河"），沿岸有瓦拉纳西等圣城③历史：古印度文明发祥地之一。'},
  {c:'地形',q:'印度向外大量输出IT人才（软件工程师），说明了？',o:['印度技术人才过剩','国内IT产业不发达','印度英语教育普及、理工科人才多，但国内就业机会不足（人口基数大）','印度不重视教育'],a:2,e:'印度IT人才外流：英语优势+大量理工科毕业生（IIT质量媲美MIT）→为欧美（尤其硅谷）输送大量软件工程师。但也反映国内高端就业机会相对不足，人才流失是印度发展的挑战之一（印裔CEO在美国硅谷极为常见）。'},
  {c:'地形',q:'印度的"宝莱坞"（Bollywood）是指？',o:['印度的IT中心','以孟买为中心的印度电影产业（全球年产电影数量最多之一）','印度体育中心','印度商业中心'],a:1,e:'宝莱坞（Bollywood=Bombay（孟买旧称）+Hollywood）：以孟买为中心的印度电影产业，年产电影约1000-2000部，是全球产量最大的电影业，以歌舞情节著称，影响遍及南亚、中东、非洲。'},
  {c:'地形',q:'印度与巴基斯坦争议的克什米尔地区，其战略价值在于？',o:['石油资源丰富','地处印度河发源地，战略位置重要（扼守中亚-南亚要道，水资源争夺）','旅游资源丰富','人口众多'],a:1,e:'克什米尔（印巴争议地区，中国也有部分主张）：①印度河发源地，掌控上游即掌控下游（巴基斯坦）用水②军事要地：连接中亚与南亚③文化：穆斯林占多数但归属印度是争端核心。1947年印巴分治以来长期冲突。'},
  {c:'地形',q:'印度农业的主要灌溉方式是？',o:['完全依赖天然降水','地下水井灌（管井灌溉）和渠道灌溉系统（部分地区大型水坝）','海水淡化','雪山融水直接灌溉'],a:1,e:'印度灌溉农业发达：①管井（抽取地下水）是最普遍方式②渠道灌溉（从河流引水，如恒河运河系统）③大型水坝（纳加尔朱纳萨加尔坝等）。灌溉在旱季（冬季）尤为重要。'},
  {c:'地形',q:'印度独立后，首任总理尼赫鲁推行的工业化模式是？',o:['完全市场化，依赖外资','以重工业和公共部门为主导的"混合经济"（计划与市场并存）','完全计划经济','纯农业立国'],a:1,e:'尼赫鲁时代（1947-1964）：推行"混合经济"——国有企业主导重工业（钢铁、机械）、基础设施；私营资本发展消费品工业；同时以"五年计划"指导经济，受苏联模式影响，保留私有制。'}
);

/* ── 七下·第八章·第四节 俄罗斯（补充 +10） ── */
window.QB_G7_C8_S4.push(
  {c:'地形',q:'俄罗斯地形总体特征是？',o:['以山地为主，地势东高西低','以平原和高原为主，总体西低东高（以乌拉尔山为界）','全是高原','全是平原'],a:1,e:'俄罗斯地形：乌拉尔山以西是东欧平原（地势低平）；以东西西伯利亚平原、中西伯利亚高原、东西伯利亚山地，总体地势西低东高。俄罗斯是世界上平原面积最大的国家之一。'},
  {c:'地形',q:'俄罗斯的贝加尔湖有何重要地位？',o:['世界面积最大的湖','世界最深（1620m）、储水量最大的淡水湖（全球淡水20%）','世界最咸的湖','世界最高的湖'],a:1,e:'贝加尔湖（西伯利亚）：①世界上最深的湖（最深处1620m）②世界上最大的淡水湖（按容积，约23.6万km³，占全球地表淡水约1/5）③被称"自然博物馆"，有大量特有物种（贝加尔海豹）。'},
  {c:'地形',q:'俄罗斯的政治经济中心都集中在欧洲部分（乌拉尔山以西），原因是？',o:['亚洲部分气候太好','亚洲部分（西伯利亚）气候严寒（冻土广布），自然条件恶劣，开发困难，历史上人类活动集中在欧洲部分','亚洲部分无资源','西伯利亚是荒漠'],a:1,e:'西伯利亚（约占俄罗斯3/4国土）：气候极端寒冷（冻土层广布），基础设施建设成本极高，人口稀少（不足1/4），主要是资源（石油天然气、煤矿）开发基地，而非政治经济中心。'},
  {c:'地形',q:'俄罗斯的"西伯利亚大铁路"（跨西伯利亚铁路）的重要意义是？',o:['连接欧亚大陆，促进东西部经济联系，开发西伯利亚资源','只用于军事运输','只用于旅游','无实际意义'],a:0,e:'跨西伯利亚铁路（约9288km，全球最长铁路）：①连通莫斯科-海参崴，横跨亚欧②促进西伯利亚资源开发③战略意义（军事调兵）④是欧亚大陆桥的重要组成部分。'},
  {c:'地形',q:'俄罗斯在全球能源市场的地位是？',o:['能源完全依赖进口','世界最大天然气出口国之一，重要石油出口国，对欧洲供应至关重要','不参与国际能源贸易','能源资源少'],a:1,e:'俄罗斯能源：石油储量世界前列（天然气储量世界第一），是最大的天然气出口国，欧洲约40%天然气来自俄罗斯（2022年乌克兰战争前）。俄乌冲突后，欧洲大幅减少对俄能源依赖。'},
  {c:'地形',q:'俄罗斯首都莫斯科是世界第几大城市圈？',o:['全球最大','欧洲最大城市，圈内人口约2000万','与北京相同大小','是南美洲最大城市'],a:1,e:'莫斯科都市圈人口约2000万（大莫斯科地区），是欧洲最大的城市，也是俄罗斯政治、经济、科技、文化中心。克里姆林宫是俄罗斯政府所在地，紧邻红场和圣巴西尔大教堂。'},
  {c:'地形',q:'俄罗斯的伏尔加河对欧洲部分俄罗斯的重要性是？',o:['伏尔加河用于灌溉沙漠','欧洲最长河流（约3530km），是俄罗斯母亲河，流经重要工业城市，是内河运输大动脉','伏尔加河有大量石油','伏尔加河发源于南部山区'],a:1,e:'伏尔加河：①欧洲最长河（约3530km）②注入里海（内流河）③流经莫斯科以东，串联伏尔加-乌拉尔工业区④俄罗斯文化象征（"母亲河"）⑤一系列水库提供水电。'},
  {c:'地形',q:'俄罗斯的核武器和军事实力如何？',o:['完全没有核武器','常规武器强大但无核武器','拥有全球最多的核弹头（约6000枚），是世界第一核大国','核武器不如美国'],a:2,e:'俄罗斯拥有约6000枚核弹头（居世界第一），是《核不扩散条约》认可的五个合法核国家之一（美、俄、中、英、法）。强大的核武库是俄罗斯维持大国地位的重要支柱。'},
  {c:'地形',q:'俄罗斯在二十世纪为科学技术做出的重大贡献包括？',o:['发明互联网','第一个发射人造地球卫星（1957年，Sputnik）和将人送入太空（1961年，加加林）','发明电话','发明飞机'],a:1,e:'苏联/俄罗斯科技成就：①1957年发射世界第一颗人造卫星（斯普特尼克1号）②1961年尤里·加加林成为第一个进入太空的人③航天技术（联盟飞船）至今仍是宇航员进出国际空间站的重要载具。'},
  {c:'地形',q:'俄罗斯文化在世界上有哪些重要影响？',o:['俄罗斯文化只在本国有影响','芭蕾舞、文学（托尔斯泰、陀思妥耶夫斯基、契诃夫）、古典音乐（柴可夫斯基）等对世界文化影响深远','俄罗斯没有知名文化成就','只有冬奥会运动'],a:1,e:'俄罗斯文化贡献：①文学：托尔斯泰（《战争与和平》）、陀思妥耶夫斯基（《罪与罚》）②音乐：柴可夫斯基（《天鹅湖》《胡桃夹子》）③芭蕾舞④建筑（克里姆林宫、圣彼得堡冬宫）等，对世界文化影响巨大。'}
);

/* ── 七下·第九章·第一节 西亚（补充 +11） ── */
window.QB_G7_C9_S1.push(
  {c:'地形',q:'波斯湾地区石油资源丰富的地质原因是？',o:['降水丰富导致有机质积累','古代这里气候温湿，生物繁盛，有机体埋于地下经漫长地质时期演变成石油','地形低洼汇聚石油','人工勘探创造了石油'],a:1,e:'石油（化石能源）形成：古代（数千万至数亿年前）大量海洋生物遗体沉积→被泥沙覆盖→在高温高压地质作用下→转化为石油和天然气。波斯湾地区地质结构特殊，有利于石油富集。'},
  {c:'地形',q:'西亚大部分地区气候干燥的原因是？',o:['纬度高，气温低','受副热带高压和大陆性气候影响，降水少；深居内陆，水汽难以进入','海拔太高','靠近极地'],a:1,e:'西亚干旱：①大部分位于副热带高压控制下（下沉气流，不易成云降雨）②内陆地区远离海洋③波斯湾沿岸夏季酷热，蒸发旺盛。少数地中海沿岸（如土耳其、以色列沿海）冬季有较多降水。'},
  {c:'地形',q:'以色列的节水农业（滴灌技术）举世闻名，原因是？',o:['以色列土地不肥沃','以色列气候干旱（年均降水200-500mm），水资源极度匮乏，被迫发展精准高效节水技术','以色列人口多','以色列能源少'],a:1,e:'以色列是农业科技强国：国土大部分是沙漠（内盖夫沙漠），年均降水少，但通过滴灌技术（管道直接滴水到植物根部，节水90%以上）、海水淡化、废水回用，将沙漠变成了可耕地，被称"沙漠农业奇迹"。'},
  {c:'地形',q:'西亚战乱频繁的主要原因是？',o:['西亚气候恶劣','战略位置重要+石油资源丰富引发大国争夺；宗教民族矛盾复杂；以巴冲突等历史遗留问题','西亚人口太多','西亚技术落后'],a:1,e:'西亚地缘政治复杂：①石油资源丰富引发大国（美俄）干预②宗教矛盾（伊斯兰教内部逊尼-什叶派、基督教、犹太教）③民族矛盾（阿拉伯、波斯、库尔德、犹太等）④以巴冲突（1948年建国以来）等历史遗留问题。'},
  {c:'地形',q:'伊朗的主要民族和宗教是？',o:['阿拉伯族，逊尼派伊斯兰教','波斯族（主体），什叶派伊斯兰教（约95%）','库尔德族，基督教','土耳其族，逊尼派伊斯兰教'],a:1,e:'伊朗：主体民族是波斯族（约60%），什叶派伊斯兰教占主导（约95%，与周边大多数阿拉伯逊尼派国家不同）。什叶-逊尼派矛盾是伊朗与沙特阿拉伯关系紧张的重要原因。'},
  {c:'地形',q:'土耳其横跨亚欧两大洲，其战略地位的核心是？',o:['人口最多','掌控博斯普鲁斯海峡和达达尼尔海峡（土耳其海峡），控制黑海进出地中海的唯一通道','农业发达','科技水平高'],a:1,e:'土耳其战略价值：土耳其海峡（博斯普鲁斯+达达尼尔海峡）是黑海（俄罗斯、乌克兰出海口）通往地中海的唯一通道，战略价值极高。土耳其据此对通过船只有重要管控权，是北约东翼重要成员。'},
  {c:'地形',q:'沙特阿拉伯是世界最大的石油出口国之一，其石油出口主要流向？',o:['只出口到欧洲','只出口到美国','主要向亚洲（中国、日本、韩国、印度）和欧美出口','只出口到非洲'],a:2,e:'沙特石油出口：约50%流向亚洲（中国是最大客户，还有日本、韩国、印度），其次是欧洲和美国。"向东看"政策使亚洲在沙特能源外交中越来越重要（沙特中国2023年签订大量能源合作协议）。'},
  {c:'地形',q:'以色列（犹太国）建立（1948年）对当地阿拉伯人的影响是？',o:['完全没有影响','大量巴勒斯坦阿拉伯人流离失所（巴勒斯坦难民），成为持续至今的以巴冲突根源','阿拉伯人欢迎以色列建国','以色列帮助了阿拉伯人'],a:1,e:'1948年以色列建国（第一次中东战争）：约70-75万巴勒斯坦阿拉伯人流离失所（"大灾难"Nakba），被迫进入难民营（加沙、约旦河西岸、黎巴嫩等），这是以巴冲突持续至今的核心历史根源。'},
  {c:'地形',q:'西亚的农业特点是？',o:['全区农业高度发达','以旱作农业和游牧业为主，局部（两河流域、尼罗河三角洲、地中海沿岸）农业条件较好','以水稻种植为主','以热带农业为主'],a:1,e:'西亚农业：大部分干旱地区以畜牧业（羊、骆驼）为主；两河流域（伊拉克）历史上灌溉农业发达（文明起源）；地中海沿岸（土耳其、以色列、黎巴嫩）种植小麦、油橄榄、柑橘等。'},
  {c:'地形',q:'OPEC（石油输出国组织）的主要职能是？',o:['推动石油进口','协调成员国石油生产，影响国际石油价格和供应','研究石油替代能源','是联合国下属机构'],a:1,e:'OPEC（欧佩克，总部维也纳）：1960年成立，成员国包括沙特、伊拉克、伊朗、阿联酋、科威特等，通过协调产量来影响国际油价。当前与俄罗斯等非欧佩克产油国组成"欧佩克+"共同管理供应。'},
  {c:'地形',q:'西亚地区的气候使得传统建筑多为？',o:['木结构房屋，高大宽敞','厚墙、小窗、白色外墙（减少热量吸收），适应干热气候','玻璃幕墙高楼','草顶茅屋'],a:1,e:'西亚传统民居适应干热气候：厚土墙（隔热）、小窗少窗（减少热风进入和散热）、白色外墙（反射阳光）、平顶（少雨不需坡顶）、内院设计（遮阴纳凉）。近现代大城市（迪拜）已大量采用现代化玻璃高楼。'}
);

/* ── 七下·第九章·第二节 欧洲西部（补充 +11） ── */
window.QB_G7_C9_S2.push(
  {c:'地形',q:'欧洲西部（西欧）主要国家包括？',o:['俄罗斯、波兰、捷克','英国、法国、德国、意大利、荷兰、比利时、西班牙、葡萄牙等','美国、加拿大、澳大利亚','日本、韩国、新加坡'],a:1,e:'西欧主要国家：英国（伦敦）、法国（巴黎）、德国（柏林）、意大利（罗马）、西班牙（马德里）、荷兰（阿姆斯特丹）、比利时（布鲁塞尔，欧盟总部）、瑞士等。'},
  {c:'地形',q:'欧盟（EU）总部所在地是？',o:['巴黎','伦敦','柏林','布鲁塞尔（比利时）——欧盟行政中心；斯特拉斯堡（法国）——欧洲议会所在地'],a:3,e:'欧盟主要机构：欧盟委员会（行政）和欧洲理事会→布鲁塞尔（比利时）；欧洲议会→斯特拉斯堡（法国）；欧洲法院→卢森堡。欧元区（2024年共20个成员国）使用统一货币欧元。'},
  {c:'地形',q:'莱茵河对西欧工业的重要作用是？',o:['只是观光旅游河流','流经德国、荷兰等工业核心区，是西欧最重要的内河航运大动脉，连接鲁尔工业区到北海鹿特丹港','只用于农业灌溉','莱茵河主要在东欧'],a:1,e:'莱茵河（约1320km）：发源阿尔卑斯山→经德国（鲁尔工业区）→荷兰→入北海（鹿特丹港）。是西欧最重要的内河航运通道，将内陆工业区与海洋连通，鹿特丹（荷兰）因此成为欧洲最大港口。'},
  {c:'地形',q:'西欧旅游业极度发达的原因，除了历史人文资源外，还有？',o:['廉价的旅游产品','严格限制旅游','完善的基础设施（交通、住宿）、高安全性、多样的自然景观（阿尔卑斯山、峡湾、地中海）','只有气候好'],a:2,e:'西欧旅游业发达综合原因：①丰富的历史文化遗产（古罗马、中世纪城堡、博物馆等）②多样的自然景观③完善的旅游基础设施④稳定的政治环境⑤强大的品牌效应（巴黎、罗马、伦敦等城市知名度极高）。'},
  {c:'地形',q:'英国脱欧（Brexit，2020年1月）的主要争议是？',o:['英国不喜欢欧元','英国认为欧盟成员身份限制了主权和移民控制，但脱欧后也失去欧盟市场的便利','英国是为了更多战争','英国经济太差无法维持会费'],a:1,e:'脱欧争议：脱欧派认为欧盟移民政策影响本国就业安全，欧盟法规限制主权，会费过高；留欧派认为单一市场带来经济利益，共同外交更有力量。脱欧后经济代价（贸易壁垒）和移民减少已显现。'},
  {c:'地形',q:'德国是欧洲最大经济体，其支柱产业是？',o:['旅游业和服务业','高端制造业（汽车：大众/宝马/奔驰、机械、化工、金融）','轻工业纺织业','农业'],a:1,e:'德国经济：以高端制造业为核心，汽车（大众、宝马、奔驰、保时捷）、精密机械、化工（拜耳、巴斯夫）、电气工程（西门子）等在全球领先。"德国制造"是高质量工业产品的代名词。'},
  {c:'地形',q:'北欧（挪威、芬兰、瑞典、丹麦）社会模式的特点是？',o:['高度市场化，贫富差距极大','高福利、高税收、高度平等（北欧模式），人类发展指数全球最高','完全计划经济','以牧业为主要经济'],a:1,e:'"北欧模式"：高税收（个人所得税50%+）→高福利（免费教育、医疗、生育福利、失业保障）→高平等（基尼系数全球最低）→高幸福感（幸福指数常居全球前列）。北欧各国人类发展指数（HDI）长期位居全球最高行列。'},
  {c:'地形',q:'西欧以温带海洋性气候为主，最著名的特产之一是？',o:['热带水果（芒果、香蕉）','奶制品和葡萄酒（法国、意大利、西班牙葡萄酒举世闻名；英国、荷兰的奶酪和黄油）','椰子油','棕榈油'],a:1,e:'西欧农业特色：①温带海洋性气候→草场丰富→畜牧业发达（奶牛、奶酪、黄油）②地中海沿岸（法国南部、意大利、西班牙）→葡萄酒（世界最大产区）、油橄榄③法国是西欧最重要的农业大国（小麦、葡萄酒）。'},
  {c:'地形',q:'欧洲西部海岸线曲折，多良港，这对西欧经济的影响是？',o:['阻碍了西欧发展','为西欧提供便利的海运条件，促进对外贸易，历史上推动了大航海和工业革命','与经济无关','只有旅游价值'],a:1,e:'西欧海岸线全球最曲折（多峡湾、河口），拥有大量天然良港（鹿特丹、汉堡、伦敦、安特卫普等），有利于：①对外贸易②历史上大航海（葡、西、英、荷）③工业革命（能源原料进口+产品出口）。'},
  {c:'地形',q:'西欧人口问题及应对策略与中国当前人口问题的相似之处是？',o:['西欧和中国都人口过多','两者都面临人口老龄化、出生率下降，应对方式均包括鼓励生育、引进移民（程度不同）','两者人口问题完全不同','中国人口在增长而西欧在减少'],a:1,e:'共同点：均面临老龄化（老年人口占比上升）和出生率下降。应对：西欧大量引进移民（劳动力）；中国放开三孩政策（2021年）并出台生育激励措施。两者都推迟退休年龄以缓解养老金压力。'},
  {c:'地形',q:'法国巴黎之所以成为世界文化之都，原因是？',o:['巴黎气候最好','面积最大','历史悠久（超2000年）、文化艺术底蕴深厚（卢浮宫、埃菲尔铁塔、凡尔赛宫、时装、美食）、国际组织云集（UNESCO等）','人口最多'],a:2,e:'巴黎文化优势：①全球最多博物馆之一（卢浮宫是最大艺术博物馆）②时装之都（LV、香奈儿、迪奥等）③美食之都（法餐列非遗）④国际组织总部（UNESCO、OECD等）⑤世界最受欢迎旅游目的地（年接待约8000万游客，位居世界前列）。'}
);

/* ── 七下·第九章·第三节 撒哈拉以南非洲（补充 +11） ── */
window.QB_G7_C9_S3.push(
  {c:'地形',q:'撒哈拉以南非洲的地形以什么为主？',o:['平原','山地','高原（"高原大陆"，平均海拔约600m）','盆地'],a:2,e:'非洲被称为"高原大陆"，撒哈拉以南非洲地形以高原为主（非洲平均海拔约600m，全球大洲中第二高，仅次于南极洲和亚洲青藏高原区），有东非高原、南非高原、埃塞俄比亚高原等。'},
  {c:'地形',q:'尼罗河的源头在哪里，最终流入哪个海？',o:['源于撒哈拉沙漠，流入大西洋','源于东非高原（维多利亚湖附近），自南向北流入地中海','源于喜马拉雅山，流入印度洋','源于西非，流入大西洋'],a:1,e:'尼罗河（约6671km）：源于东非高原（布隆迪和卢旺达边境及维多利亚湖地区），自南向北流经乌干达、苏丹、埃及，最后流入地中海。是非洲最长河流，哺育了古埃及文明。'},
  {c:'地形',q:'刚果河（扎伊尔河）的特点是？',o:['流量小，非洲最短','非洲流量最大的河流（雨林区，流量仅次于亚马逊），是世界第二大流量河','世界最长河','完全在沙漠中流淌'],a:1,e:'刚果河：长约4700km，流域覆盖刚果盆地（热带雨林），年均流量约41000立方米/秒，是世界流量第二大河（仅次于亚马逊），水能资源极丰富，横跨赤道，全年流量平稳。'},
  {c:'地形',q:'非洲东部的大裂谷（东非大裂谷）的形成原因是？',o:['流水侵蚀','亚欧板块与非洲板块碰撞','非洲板块内部张裂（南北向断层下陷）','冰川侵蚀'],a:2,e:'东非大裂谷：非洲板块内部张裂（地壳断裂下陷）形成，长约6000km，宽50-100km，深600-2000m，是世界上最长的陆地裂谷。裂谷内有大量深水湖（坦噶尼喀湖、马拉维湖等），维多利亚湖在其旁。'},
  {c:'地形',q:'撒哈拉以南非洲面临的"人口爆炸"问题，主要影响是？',o:['促进经济快速发展','人口增长速度远超经济增长，加剧粮食短缺、贫困、生态破坏、教育医疗资源不足','使劳动力充足，利大于弊','与经济发展无关'],a:1,e:'撒哈拉以南非洲人口增长率约2.5-3%（全球最高），人口增长远超粮食生产和经济增长→加剧贫困、饥荒、教育医疗资源匮乏、生态破坏（过度开垦放牧）→形成恶性循环。'},
  {c:'地形',q:'非洲的"彩虹之国"是哪个国家？为何有此美称？',o:['肯尼亚，因为自然景色美丽','南非，因为废除种族隔离后，多种族共存（黑、白、有色、印裔），象征多元文化社会','尼日利亚，因为首都色彩丰富','埃塞俄比亚，因为高原气候'],a:1,e:'"彩虹之国"南非：1994年曼德拉领导的非洲人国民大会赢得首次多种族选举，种族隔离制度结束。南非有黑人（80%）、白人（8%）、有色人种（9%）、印度裔（2%），11种官方语言，是非洲最多元化的国家，被称"彩虹之国"。'},
  {c:'地形',q:'撒哈拉以南非洲的矿产资源极为丰富，其中尤为突出的是？',o:['煤炭和天然气','钻石和黄金（南非约占世界黄金储量约50%，刚果金钴矿占全球60%+）','铁矿石','铀矿'],a:1,e:'非洲矿产：南非→黄金（历史上产量全球第一）、钻石（联合矿业Diamond Fields）；刚果民主共和国→钴矿（全球电动车电池关键原材料，产量占全球60%+）；赞比亚→铜；尼日利亚、安哥拉→石油。'},
  {c:'地形',q:'艾滋病（HIV/AIDS）在撒哈拉以南非洲肆虐的主要原因是？',o:['气候导致','政治因素','贫困导致医疗资源不足、教育匮乏（防治知识不足）、传统文化等多因素叠加','水质问题'],a:2,e:'非洲艾滋病高发：①贫困→医疗资源严重不足（无法获得抗逆转录病毒药物）②性教育和防治知识缺乏③针具共用④部分传统习俗增加传播风险。南非、博茨瓦纳、莱索托成年人HIV感染率超20%，是人类发展的重大阻碍。'},
  {c:'地形',q:'非洲野生动物（大象、狮子、长颈鹿等）保护面临的主要威胁是？',o:['气候变化（唯一原因）','栖息地丧失（农业扩张、砍伐森林）、偷猎（象牙、犀牛角）、人兽冲突','食物不足','水资源过多'],a:1,e:'非洲野生动物威胁：①栖息地破坏（农业开荒、人口扩张）②偷猎（象牙走私→中国、东南亚市场；犀牛角）③人兽冲突（大象破坏农作物被农民猎杀）④气候变化（干旱加剧）。东非国家公园（肯尼亚、坦桑尼亚）是重要保育地。'},
  {c:'地形',q:'非洲最大经济体是哪个国家？',o:['南非','埃及','尼日利亚（约GDP5000亿美元，2022年）','埃塞俄比亚'],a:2,e:'尼日利亚是非洲人口最多（约2.2亿）、经济体量最大的国家，石油出口是主要收入来源。但经济发展不均衡，贫困率仍高。南非是非洲工业化程度最高的国家，人均GDP高于尼日利亚。'},
  {c:'地形',q:'马达加斯加岛被称为"生物进化博物馆"，原因是？',o:['有恐龙化石','数千万年前与非洲大陆分离，独立演化出大量特有物种（如狐猴，占世界狐猴100%）','气候最特殊','是最大的岛屿'],a:1,e:'马达加斯加（世界第四大岛）约8000万年前从非洲大陆分离，长期独立演化，形成大量特有物种：狐猴（超100种，全球独有）、变色龙（全球约一半物种）、猴面包树等。然而大规模砍伐正使这些物种面临灭绝威胁。'}
);

/* ── 七下·第九章·第四节 澳大利亚（补充 +11） ── */
window.QB_G7_C9_S4.push(
  {c:'地形',q:'澳大利亚面积居世界第几？',o:['第四','第五','第六（约769万平方千米）','第七'],a:2,e:'澳大利亚面积约769万平方千米，居世界第六（仅次于俄罗斯、加拿大、美国、中国、巴西），是大洋洲面积最大的国家，也是南半球面积最大的国家。'},
  {c:'地形',q:'澳大利亚大堡礁是什么？',o:['山脉名称','世界上最大的珊瑚礁系统（约2300km），列入世界自然遗产','湖泊群','沙漠地带'],a:1,e:'大堡礁（澳大利亚昆士兰州东北沿海）：全球最大珊瑚礁系统，长约2300km，面积约35万km²，是地球上最大的生物构造（由珊瑚虫骨骼堆积而成），1981年列入UNESCO世界自然遗产，因气候变暖（海水升温白化）而受到严重威胁。'},
  {c:'地形',q:'澳大利亚为什么被称为"坐在矿车上的国家"？',o:['采矿业危险性大','矿产资源极其丰富（铁矿石、煤炭、铝土矿、黄金、锂等全球领先）并大量出口','澳大利亚人喜欢采矿','矿车是主要交通工具'],a:1,e:'澳大利亚矿产资源：铁矿石（储量全球第一，年出口约9亿吨）、煤炭（最大出口国之一）、铝土矿（全球最大）、黄金（全球前三）、锂（全球最大），矿产出口占澳出口总额约50%以上，"矿业国"称号名副其实。'},
  {c:'地形',q:'澳大利亚首都是？',o:['悉尼','墨尔本','堪培拉（专门建设的政治首都）','布里斯班'],a:2,e:'堪培拉是澳大利亚首都，位于新南威尔士州内。因悉尼（新南威尔士州）和墨尔本（维多利亚州）竞争首都，两州妥协在两者之间建设新城堪培拉作为首都（1913年奠基，1927年议会迁入）。'},
  {c:'地形',q:'澳大利亚的气候分布有何特点？',o:['全境以热带气候为主','由北（热带）向南（温带）过渡，中部大陆内部以热带沙漠为主（半环形分布）','全境温带海洋性气候','全境以温带大陆性气候为主'],a:1,e:'澳大利亚气候："半环形"分布：①北部（热带季风/热带草原）②东南部（温带/亚热带湿润）③西南（地中海）④中部和西部（热带沙漠，面积最大，约1/3国土年降水<250mm）。'},
  {c:'地形',q:'澳大利亚城市主要集中在哪里？',o:['内陆沙漠地区','北部热带地区','东南部和西南部沿海（气候温和，是历史上欧洲移民定居地）','中部高原'],a:2,e:'澳大利亚约90%人口集中在东南部（悉尼、墨尔本、布里斯班、堪培拉）和西南部（珀斯、阿德莱德）沿海，内陆干旱地区人口极稀少。这是"人口分布严重不均"的典型案例。'},
  {c:'地形',q:'澳大利亚土著居民（Aboriginal）的困境是？',o:['他们是澳大利亚人口主体，生活富裕','自欧洲殖民以来，遭受歧视和剥夺，土地被占，至今仍是澳大利亚最边缘化群体（贫困率、失业率、健康问题远高于平均水平）','完全融入主流社会','人口在增长，生活水平提高'],a:1,e:'澳洲土著：约6.5万年前从非洲迁徙而来，是世界上最古老的文化之一。1788年英国殖民后遭受屠杀、土地剥夺和歧视（"白澳政策"）。今天仍面临：极高贫困率和失业率、预期寿命比非土著低约8年、高监禁率等严重问题。2008年澳政府正式道歉（Kevin Rudd向土著人道歉）。'},
  {c:'地形',q:'澳大利亚是世界上人口密度最小的大洲（指有人居住的大洲）之一，原因是？',o:['澳大利亚国土面积小','国土面积大，但中部和西部大面积沙漠和干旱地区不适合居住，可居住面积有限','人口政策限制','经济太落后'],a:1,e:'澳大利亚人口约2700万（2024年），国土约769万km²，平均人口密度约3.5人/km²（全球最低之一）。主要原因：大面积内陆沙漠（中部沙漠、西澳荒漠）人迹罕至，可居住面积相对有限。'},
  {c:'地形',q:'新西兰（澳大利亚东南邻国）以什么著名？',o:['石油出口','钻石开采','壮丽自然景观（峡湾、雪山、绿地）和畜牧业（奶制品出口全球第一），曾是《魔戒》的拍摄地','高科技产业'],a:2,e:'新西兰：①自然景观壮美（南岛峡湾国家公园、火山温泉）②畜牧业（奶制品出口全球最大之一，恒天然FONTERRA）③高质量农产品（奇异果、羊肉）④因《魔戒》《霍比特人》拍摄而享誉全球旅游目的地。'},
  {c:'地形',q:'澳大利亚的农业结构是？',o:['以水稻种植为主','以小麦种植和牛羊畜牧业为主，农业高度机械化，农场规模大','以热带水果为主','以渔业为主'],a:1,e:'澳大利亚农业：①小麦（主产区：西澳和东南部）——世界重要小麦出口国②牛肉（规模化牧场）③羊毛（历史支柱，如今仍重要）④奶制品⑤甘蔗（昆士兰）。农业高度机械化，劳动力少但效率高（每个农业工人服务面积远超亚洲农民）。'},
  {c:'地形',q:'澳大利亚政府向中国出口铁矿石和煤炭，这反映了？',o:['澳大利亚是发展中国家','国际贸易中的资源互补和比较优势，中国是澳大利亚最大贸易伙伴','澳大利亚没有制造业','铁矿石是最重要的商品'],a:1,e:'中澳贸易：澳大利亚出口铁矿石、煤炭、LNG、农产品等（资源和初级产品）→中国；中国出口机械、电子、消费品等→澳大利亚。中国是澳最大贸易伙伴（出口目的地约33%）。这体现了国际分工和比较优势原则。'}
);

/* ── 七下·第十章·第一节 美国（补充 +11） ── */
window.QB_G7_C10_S1.push(
  {c:'地形',q:'美国的地形从西到东依次是？',o:['平原→山地→高原','西部山地（落基山脉）→中部平原（密西西比河流域）→东部阿巴拉契亚山地','高原→平原→山地','山地→平原→山地'],a:1,e:'美国地形三部分（西→东）：①西部：落基山脉等（年轻山地，多火山地震）②中部：大平原（密西西比河冲积，是世界最重要农业区之一）③东部：阿巴拉契亚山地（古老，高度较低）。'},
  {c:'地形',q:'美国五大湖对美国的意义是？',o:['只是旅游资源','提供大量淡水资源，发达的内河航运，促进五大湖工业区（钢铁、汽车等）的发展','只有渔业价值','对美国经济影响微小'],a:1,e:'五大湖（苏、密、休、伊、安大略湖）：①全球最大淡水湖群（储水量约占全球地表淡水约21%）②通过圣劳伦斯河入大西洋③内河航运发达（煤铁矿运输）④沿湖形成五大湖工业带（芝加哥、底特律、克利夫兰）。'},
  {c:'地形',q:'美国的密西西比河在农业上的重要作用是？',o:['只用于旅游','贯穿中部大平原，提供灌溉水源，内河运输（农产品向南输送），中部"粮仓"的重要水利保障','只有航运功能','对农业没有影响'],a:1,e:'密西西比河（约6020km，北美最长河）：①流经中部大平原农业核心区②提供农业灌溉水源③主要内河航运通道（粮食、煤炭等大宗货物南运至新奥尔良港出口）④历史上推动了中部大平原的农业开发。'},
  {c:'地形',q:'美国是移民国家，其文化特点是？',o:['美国文化单一统一','多元文化社会（"民族大熔炉"或"民族沙拉盆"）——融合了欧洲、非洲、亚洲、拉美等文化','只有欧洲文化','只有英国文化'],a:1,e:'美国文化：由来自世界各地的移民共同创造的多元文化（"文化大熔炉"）。英裔白人（主体，约60%）、西班牙裔（约18%，快速增长）、非洲裔（约13%）、亚裔（约6%）等共同构成。节日、饮食、音乐、宗教极度多元。'},
  {c:'地形',q:'美国的"硅谷"（Silicon Valley）之所以能聚集全球顶尖科技公司，主要原因是？',o:['硅谷靠近海洋，气候好','斯坦福大学等顶级高校提供人才和研究成果、风险投资文化、创业生态系统、宜人气候','硅谷资源丰富','政府政策补贴'],a:1,e:'硅谷成功因素：①斯坦福大学（及伯克利等）提供顶尖人才②发达的风险投资文化③成熟的创业生态（失败可接受、成功经验可复制）④加州气候宜人吸引人才⑤历史上军事/航天投资打下基础（惠普、仙童半导体等起源于此）。'},
  {c:'地形',q:'美国在全球经济中的霸主地位，除GDP外，还体现在？',o:['只体现在GDP','美元作为全球储备货币（占全球外汇储备约58%）、跨国公司（苹果、谷歌、亚马逊等）、金融市场（纽约证交所、纳斯达克）规模全球最大','只体现在军事','只体现在人口'],a:1,e:'美国经济霸权：①美元是全球储备货币（布雷顿森林体系遗产）②华尔街（纽约）是全球最大金融中心③苹果、谷歌、微软、亚马逊等科技巨头市值全球领先④石油、军工、航空等多领域主导地位。'},
  {c:'地形',q:'美国的农业生产特点是？',o:['以传统小农经营为主','高度机械化、大规模农场经营（农业人口<2%，养活全国+大量出口）、农业科技水平极高','劳动密集型','以手工劳作为主'],a:1,e:'美国农业：①大规模机械化农场（平均农场面积约180公顷）②农业人口仅占总人口约1.5%③先进农业科技（转基因、精准农业、卫星导航农机）④是全球最大农产品出口国之一（大豆、玉米、小麦）。'},
  {c:'地形',q:'美国的航天和军事科技水平如何？',o:['落后于俄罗斯和中国','在航天（NASA）、军费（全球最高约8000亿美元/年）、军事技术（隐形飞机、航母）等方面仍居全球领先地位','完全没有航天能力','只有核武器'],a:1,e:'美国军事科技：①NASA是全球航天技术最强（阿波罗登月、火星探测、詹姆斯·韦伯望远镜）②年军费约7000-8000亿美元（全球第一）③拥有11艘核动力航母（全球最多）④F-35隐形战机、核武器等领先。Space X（马斯克）等私人航天也蓬勃发展。'},
  {c:'地形',q:'美国的国家公园体系（如黄石、大峡谷）有何重要意义？',o:['只是旅游景点','首创"国家公园"概念（1872年黄石国家公园，世界第一个国家公园），保护自然生态系统，有重要环境和科学研究价值','占地太多影响农业','只有经济价值'],a:1,e:'美国国家公园体系（含423个单位）：①1872年黄石——世界上第一个国家公园（保护野生动物、地热奇观）②保护了生物多样性和生态系统③成为各国效仿的自然保护模式④大峡谷、约塞米蒂等吸引全球游客（年接待约3亿人次）。'},
  {c:'地形',q:'美国洛杉矶（好莱坞）是全球最重要的什么产业中心？',o:['汽车制造','钢铁工业','影视娱乐（好莱坞电影/电视产业）和航空航天（波音等）','石油化工'],a:2,e:'洛杉矶：①好莱坞——全球最具影响力的电影产业中心（迪士尼、环球、华纳等）②航空航天（波音洛杉矶工厂、JPL太空实验室）③港口（长滩/洛杉矶港是美国最大港口，大量对亚贸易）④美国第二大都市圈（约1300万人）。'}
);

/* ── 七下·第十章·第二节 巴西（补充 +11） ── */
window.QB_G7_C10_S2.push(
  {c:'地形',q:'巴西的国土面积居世界第几？',o:['第四','第五（约851万平方千米）','第六','第三'],a:1,e:'巴西面积约851万平方千米，居世界第五（俄罗斯、加拿大、美国、中国之后），是南美洲面积最大的国家，约占南美洲大陆面积48%。'},
  {c:'地形',q:'巴西经济的多元化特点体现在？',o:['只依赖农业','只依赖矿产出口','农业（大豆、咖啡、牛肉全球出口领先）、工业（飞机、钢铁、石化）和服务业均衡发展，是南美最大经济体','只依赖石油'],a:2,e:'巴西是南美最大、全球第九大经济体：①农业出口大国（大豆第一、牛肉第一、咖啡第一、鸡肉第二）②工业（农业机械、飞机——巴西航空工业EMBRAER全球第三大飞机制造商）③服务业占GDP约70%。'},
  {c:'地形',q:'里约热内卢的"狂欢节"（嘉年华）是世界规模最大的狂欢活动，根源是？',o:['巴西政府举办的政治活动','源自葡萄牙殖民带来的天主教文化（大斋期前的狂欢传统），与非洲奴隶带来的桑巴舞融合，形成独特巴西文化','里约市的商业活动','为了吸引旅游设计的活动'],a:1,e:'里约狂欢节（嘉年华）：源于葡萄牙天主教"告别肉食"的大斋期前节日，与非洲奴隶带来的桑巴舞蹈节奏、服装文化融合，形成独特的巴西嘉年华文化，每年吸引200万+游客，是世界最大规模的单一节日活动。'},
  {c:'地形',q:'巴西的贫富差距问题突出，"贫民窟"（Favela）现象的原因是？',o:['巴西人口太少','城市化过快（大量农村人口涌入城市）但城市正规就业和住房不足，贫富分化严重','巴西气候恶劣','政府政策完善但人们不愿工作'],a:1,e:'巴西贫民窟（Favela）：殖民历史遗留的社会不平等（奴隶制）+快速城市化（农村人口大量进入圣保罗、里约）但城市无法提供足够就业和住房→非正规住区（贫民窟）。巴西基尼系数长期居全球最高之列，贫富分化是重要社会问题。'},
  {c:'地形',q:'巴西大豆产业的崛起，对亚马逊雨林有何影响？',o:['没有影响','大豆种植园扩张是亚马逊雨林砍伐的主要驱动力之一（与牧场扩张共同造成80%+的雨林砍伐）','促进了雨林的保护','大豆种植在沿海地区与雨林无关'],a:1,e:'亚马逊雨林砍伐主因：①大豆种植园扩张（巴西大豆出口中国等市场需求推动）②牛肉生产（牧场扩张，占砍伐面积最大）③木材开采④违法定居点。中国是巴西大豆最大买家，也间接推动了这一矛盾。'},
  {c:'地形',q:'巴西的圣保罗是南美洲最大城市，其主要功能是？',o:['政治首都','巴西最大工业城市和金融中心（南美最大金融市场），人口约1200万（大圣保罗超2200万）','主要旅游城市','主要港口城市'],a:1,e:'圣保罗：①巴西和南美最大城市②南美最大工业城市（汽车、食品、纺织、电子）③金融中心（巴西证券交易所B3、众多跨国公司南美总部）④GDP约占巴西全国GDP约1/3。首都是巴西利亚（1960年迁都），里约是著名旅游城市。'},
  {c:'地形',q:'巴西利亚（Brasília）成为巴西首都的原因是？',o:['巴西利亚是最大城市','为开发内陆地区、均衡区域发展，1956年在内陆高原新建首都（1960年迁都）','巴西利亚靠近赤道','气候最好'],a:1,e:'巴西迁都巴西利亚（1960年）：总统儒塞利诺·库比契克推动，目的是：①促进巴西内陆开发（原首都里约在沿海）②吸引人口向内陆移动③象征"新巴西"的国家建设意志。巴西利亚由规划师科斯塔和建筑师尼迈耶设计，1987年列入世界文化遗产。'},
  {c:'地形',q:'巴西的种族构成是？',o:['全部是欧洲裔白人','全部是非洲裔黑人','欧洲裔（约48%）、混血（约43%）、非洲裔（约8%）、亚裔等多元种族（华人和日裔约140万）','以印第安原住民为主'],a:2,e:'巴西种族：①欧洲裔（葡萄牙、意大利、德国等）约48%②混血（Pardo，欧非印混血）约43%③非洲裔（黑人）约8%④亚裔（日裔约150万，是巴西以外最大日裔社区）约1%。印第安原住民现仅约90万（约0.5%），历史上大量被殖民杀害或同化。'},
  {c:'地形',q:'巴西足球文化如此繁荣，与地理和历史有何关联？',o:['与地理历史无关，只是偶然','葡萄牙殖民带来足球+黑人奴隶后代的身体特质+贫民窟文化（足球是贫困孩子最易获得的娱乐和上升通道）→形成独特巴西足球文化','气候好适合踢足球','政府强制推广'],a:1,e:'巴西足球文化：①葡萄牙人20世纪初带来足球运动②非裔巴西人的创造性技巧融入（起源贫民窟的技术华丽风格"Jogo Bonito"）③成为贫困阶层改变命运的途径④国家支持（1950年、2014年世界杯主办）。巴西5次赢得世界杯（最多），被称"足球王国"。'},
  {c:'地形',q:'巴西是BRICS（金砖五国）之一，其国际影响力体现在？',o:['巴西只是南美小国','南美政治大国（主导南共市MERCOSUR）、气候谈判重要角色（亚马逊雨林的全球意义）、G20成员、2014年世界杯+2016年里约奥运会主办','巴西无国际影响','只有足球影响'],a:1,e:'巴西国际地位：①南共市（MERCOSUR）核心成员②气候变化谈判中掌握"亚马逊牌"（保护/破坏雨林对全球影响）③G20成员④BRICS（金砖国家）创始成员⑤世界最大蔗糖、大豆、牛肉出口国，农业国际话语权大。'},
  {c:'地形',q:'巴西的可再生能源利用在全球领先，主要表现是？',o:['太阳能发电量全球第一','核电占比最大','水力发电（伊泰普水电站等）占电力来源约65%，并大规模使用甘蔗乙醇替代汽油','风能占比最大'],a:2,e:'巴西可再生能源：①水力发电约65%（伊泰普水电站，装机容量曾是世界最大）②甘蔗乙醇：1970年代石油危机后大规模推广，今天巴西是世界第二大乙醇燃料生产国（仅次于美国），约一半汽车使用乙醇或弹性燃料。巴西是可再生能源利用最广泛的大国之一。'}
);

/* ── 七下·第十一章 极地地区（补充 +10） ── */
window.QB_G7_C11.push(
  {c:'地形',q:'南极洲的"最"：以下哪条不正确？',o:['平均海拔最高（约2300m）','年平均气温最低（约-25°C）','降水量最多','风力最大（"风极"，极风80-100m/s，最大可达130m/s）'],a:2,e:'南极洲降水量极少（年均降水约55mm，是全球最干燥的大洲之一），但因气温极低蒸发极少，积累了大量冰雪。南极是降水最少而非最多的大洲（降水最多的大洲是南美洲）。'},
  {c:'地形',q:'北极熊和企鹅分别在哪极？',o:['都在南极','都在北极','北极熊在北极，企鹅在南极（两者从未在野生状态下相遇）','北极熊在南极，企鹅在北极'],a:2,e:'北极熊（白熊）：北极地区（北冰洋沿岸，以浮冰为家，捕猎海豹）。企鹅：南极洲（所有野生企鹅均在南半球，以南极为主）。两者在自然状态下生活在地球两端，从未相遇（除非在动物园）。'},
  {c:'地形',q:'南极洲的《南极条约》（1959年）规定了什么？',o:['谁先到达南极谁拥有主权','禁止军事活动和核试验，保护南极环境，所有国家均可用于和平科学研究，冻结领土主张','只有科学研究国家可进入','南极属于联合国管辖'],a:1,e:'《南极条约》（1959年，1961年生效，现57个缔约国）核心内容：①冻结领土主权主张（不承认也不否认任何国家的领土主张）②禁止一切军事活动和核试验③保护南极环境（禁止采矿，1991年《马德里议定书》）④科学研究对所有国家开放、成果共享。'},
  {c:'地形',q:'中国在南极建立的科学考察站有哪些？',o:['只有长城站','长城站（南设得兰群岛）、中山站（东南极）、昆仑站（冰穹A，海拔最高站）、泰山站（2014年），秦岭站（2024年）','只有中山站','只有昆仑站'],a:1,e:'中国南极科考站：①长城站（1985年，南设得兰群岛，62°S）②中山站（1989年，东南极，69°S）③昆仑站（2009年，冰穹A，4087m，南极内陆最高站）④泰山站（2014年，中继站）⑤秦岭站（2024年，罗斯海新站）。'},
  {c:'地形',q:'全球变暖对极地地区的最直接影响是？',o:['极地气温升高但影响不大','极地冰盖和冰川融化加速→海平面上升→沿海城市和低地国家受威胁；北冰洋海冰减少→航道开通→生态系统改变','极地降水增多','极地气候更加适合居住'],a:1,e:'气候变暖对极地影响：①南极冰盖和格陵兰冰川融化→海平面上升（预计2100年升高0.5-1m+，威胁孟加拉、荷兰、太平洋岛国等）②北极海冰面积减少（每十年减少约13%）→东北/西北航道开通③北极熊栖息地消失④永久冻土融化→甲烷释放（正反馈）。'},
  {c:'地形',q:'北冰洋"东北航道"（北方海航道）开通后的意义是？',o:['只对俄罗斯有意义','从东亚（中国/日本）到西欧的航程将比经马六甲→苏伊士运河缩短约40%（约7000km），战略和经济价值极大','只是旅游路线','对环境友好'],a:1,e:'北方海航道（俄罗斯北部沿岸）：若全年通航，中国上海→荷兰鹿特丹约16000km（传统苏伊士运河路线约22000km），节约燃油和时间约30-40%。中国积极推进"冰上丝绸之路"战略。但也带来生态风险（石油泄漏、噪音影响北极野生动物）。'},
  {c:'地形',q:'南极洲的科考意义主要体现在？',o:['提供大量矿产资源（已大规模开采）','是研究全球气候变化、大气科学、天文学、生命极限等的天然实验室；冰芯可记录数十万年气候历史','只有旅游价值','只有军事价值'],a:1,e:'南极科研价值：①冰芯（钻取古老冰层）：记录80万年气候和大气成分变化历史②极端环境：研究生命极限（极地微生物、嗜冷生物）③天文：南极天文台得天独厚（极昼、无光污染、干燥大气）④臭氧层：南极臭氧空洞的发现（1985年）推动《蒙特利尔议定书》。'},
  {c:'地形',q:'北极地区和南极洲的气候对比：哪个更冷？',o:['北极更冷','一样冷','南极更冷（年均约-25℃，最低达-89.2℃），因为南极是大陆，海拔高、散热快；北极是海洋，海水有一定热储量','因季节不同无法比较'],a:2,e:'南极比北极更冷：①南极是大陆（海拔平均2300m），比北冰洋（海洋，有热储量）散热快②南极面积大，大陆性强③记录最低气温：南极约-89.2℃（沃斯托克站，1983年）；北极约-67.8℃（格陵兰岛）。'},
  {c:'地形',q:'极地臭氧空洞主要出现在哪个极？原因是？',o:['北极（北冰洋）','南极（南极洲上空），因为南极极涡更强更稳定，使CFCs（氟利昂）破坏臭氧的化学反应更有效','两极都一样严重','赤道附近'],a:1,e:'南极臭氧空洞：南极极涡（极强的环绕南极的高空气流）锁住冷空气，使极地平流层极度寒冷（-80℃），在极涡云（极地平流层云）表面CFCs（氟利昂）分解臭氧的化学反应尤为高效，因此每年南极春季（9-10月）臭氧空洞最严重。《蒙特利尔议定书》（1987年）后臭氧层正在缓慢恢复。'},
  {c:'地形',q:'参加南极科考的人员需要接受哪些准备？',o:['无需特别准备','需接受极地生存培训（低温防护、冻伤预防）、极端天气应对、南极条约规定（保护环境不带入外来物种）、医疗急救等','只需要会踢足球','只需要学习英语'],a:1,e:'南极科考准备：①极地生存技能（冻伤/低温预防，暴风雪应对）②心理适应（极昼极夜、与世隔绝长期驻站）③《南极条约》/《马德里议定书》规范（禁止带入外来物种，废弃物全部带回）④专业科研技能⑤体检（健康状况要求高，南极无法及时医疗撤离）。'}
);

/* ── 七下期中模拟（补充 +9） ── */
window.QB_G7_7B_MID.push(
  {c:'地形',q:'日本是世界第三大经济体，其最大的弱点是？',o:['技术落后','人口太多','自然资源极度匮乏，高度依赖进口原材料（石油>99%进口，铁矿石>100%进口）','气候不稳定'],a:2,e:'日本经济的"阿喀琉斯之踵"：几乎所有工业原材料（石油、天然气、铁矿石、煤炭、铜等）均依赖进口，一旦海上运输受阻（马六甲海峡、霍尔木兹海峡），日本经济将面临严重冲击，这是日本高度重视海洋安全的根本原因。'},
  {c:'地形',q:'东南亚的华人华侨（海外华人）主要集中在哪些国家？',o:['只在菲律宾','新加坡（华人占74%）、马来西亚（华人占约24%）、泰国（约14%）、印尼（约3%但约800万）等','只在越南','只在印度尼西亚'],a:1,e:'东南亚是全球华人华侨最集中的地区：①新加坡华人占总人口约74%（实际是中华文化主导国家）②马来西亚约24%（约700万）③泰国约14%（约650万）④印尼约3%（约800万，人数最多）。华人华侨在东南亚经济中发挥重要作用。'},
  {c:'地形',q:'印度的恒河被视为圣河，发生的严重问题是？',o:['恒河水量太少','恒河水质受到严重污染（工业废水、生活污水、宗教活动废弃物）威胁数亿依赖其饮用水的人口','恒河没有洪水问题','恒河已经干涸'],a:1,e:'恒河污染：沿岸约5亿人口的工业废水、未处理生活污水、农业化肥农药径流、火葬灰烬排放→恒河成为世界污染最严重的河流之一。印度政府推出"清洁恒河"（Namami Gange）计划，但治理进展缓慢，是印度最严峻的环境挑战之一。'},
  {c:'地形',q:'俄罗斯的天然气主要通过什么方式出口到欧洲？',o:['船运LNG（液化天然气）','管道（北溪、土耳其溪等管道系统）和部分LNG出口','铁路运输','航空运输'],a:1,e:'俄欧天然气：主要通过横跨乌克兰或波罗的海的长输管道（北溪1号已被炸毁，2022年）直接输往欧洲，极少量以LNG（液化天然气）船运方式。俄乌战争后，欧洲大力建设LNG进口终端，减少对俄管道气依赖。'},
  {c:'地形',q:'西亚的"阿拉伯之春"（2011年）说明了什么地理和社会问题？',o:['西亚气候越来越恶劣','政治经济不平等、高失业率（尤其青年失业）、专制统治，在社交媒体传播下引发大规模政治动荡','西亚人口减少','西亚石油枯竭'],a:1,e:'"阿拉伯之春"（2010-2012年）：突尼斯、埃及、利比亚、叙利亚等国大规模抗议，根本原因：①高青年失业率（30-50%）②贫富差距和腐败③专制政权④粮食价格上涨（气候变化+生物能源需求推高国际粮价）。社交媒体是重要传播工具。'},
  {c:'地形',q:'欧洲西部是否有大量自然资源？现代工业发展依赖什么？',o:['西欧有丰富石油（北海）、煤炭、铁矿等历史资源，现代仍自给','历史上依靠殖民地资源；现代主要依赖进口原料（从非洲、中东、澳大利亚等），出口高附加值工业品和服务','西欧完全不进口资源','西欧以农业为主，不需要工业资源'],a:1,e:'西欧资源：历史上煤铁丰富（鲁尔区、洛林铁矿）支持工业革命；现代传统矿产已大量耗尽（鲁尔钢铁衰落），北海石油（英国、挪威）仍重要，但总体需大量进口原材料，出口汽车、机械、医药、金融服务等高附加值产品和服务。'},
  {c:'地形',q:'撒哈拉以南非洲的荒漠化扩展，与哪些人类活动有关？',o:['工业污染','过度砍伐林木、过度放牧、不合理耕作导致土地退化，加速荒漠向南扩展（萨赫勒地区最严重）','核试验','采矿活动'],a:1,e:'非洲荒漠化（萨赫勒地区——撒哈拉南缘最严重）：①过度放牧（牲畜超出土地承载力）②滥砍滥伐（燃料木材）③不当耕作（土壤侵蚀）④气候变暖（降水减少）。荒漠每年南扩约5km，严重威胁粮食安全。"绿色长城"（非洲之角到塞内加尔的植被带）是应对措施。'},
  {c:'地形',q:'澳大利亚的大堡礁因气候变暖面临的主要威胁是？',o:['台风频繁','旅游者破坏','海水温度升高导致珊瑚白化（共生藻类离开→珊瑚变白死亡），大堡礁50%以上珊瑚礁已经白化','工业污染直接侵蚀'],a:2,e:'珊瑚白化：海水温度升高1-2°C以上→珊瑚虫排出共生虫黄藻→珊瑚失去颜色（白化）→无法光合作用→死亡。2016-2017年大堡礁发生大规模白化事件，超50%珊瑚死亡。若全球升温2°C以上，99%珊瑚礁将消失。'},
  {c:'地形',q:'巴西的亚马逊河有何特别之处？',o:['流量最少','亚马逊河是世界上流量最大的河流（约占全球河流入海总流量约20%），也是流域面积最广之一','世界最长的河流','只流经巴西境内'],a:1,e:'亚马逊河：①流量最大（年均流量约22万立方米/秒，约占全球所有河流总流量15-20%）②流域面积约705万km²（全球第二，仅次于刚果河流域按比例）③发源于安第斯山，流入大西洋④流经热带雨林，生物多样性极丰富⑤流经巴西、秘鲁、哥伦比亚等国。'}
);

/* ── 七下期末模拟（补充 +9） ── */
window.QB_G7_7B_FIN.push(
  {c:'地形',q:'亚洲的气候与非洲气候相比，最显著的区别是？',o:['亚洲比非洲更热','亚洲季风气候显著（受海陆热力差异影响大），非洲气候以热带气候为主、纬向分布规律明显','亚洲降水比非洲更少','亚洲没有沙漠'],a:1,e:'亚洲最显著特点：大陆面积大，海陆差异明显→季风气候（东亚、南亚）显著，大陆内部温带大陆性气候广布。非洲特点：南北对称分布，以热带气候为主（约80%国土位于南北回归线之间），季风不如亚洲明显。'},
  {c:'地形',q:'发展中国家为何难以快速进入高科技产业？',o:['不需要科技','科技与他们无关','基础设施差、教育水平低、研发投入少、知识产权保护弱等多重障碍','发展中国家都是农业国'],a:2,e:'发展中国家科技发展障碍：①教育水平（基础教育普及率低，高等教育资金不足）②研发投入不足（R&D占GDP比例低）③人才外流（脑drain）到发达国家④知识产权保护弱⑤资金、基础设施不足⑥起步晚，技术差距大。但少数国家（中国、印度、巴西）已实现跨越式发展。'},
  {c:'地形',q:'全球化背景下，"世界工厂"的角色已经从日本→"亚洲四小龙"→中国→逐渐向哪里转移？',o:['向欧洲转移','向非洲南部转移','向东南亚（越南、孟加拉等）和南亚（印度、巴基斯坦）等劳动力更廉价的地区转移','制造业已经消亡'],a:2,e:'"世界工厂"转移路径：随着劳动力成本上升，制造业从高成本地区（日本→韩国/台湾→中国东部沿海）向低成本地区转移。近年向越南（耐克、三星等）、孟加拉（纺织）、印度（苹果组装）等国转移，但中国凭借完整供应链和高效率仍保持优势。'},
  {c:'地形',q:'以下是七年级地理核心概念配对，哪个是错误的？',o:['地中海气候——夏干热冬温湿','赤道附近——热带雨林气候','温带大陆性气候——全年温和湿润','板块张裂——形成裂谷和海洋'],a:2,e:'"温带大陆性气候——全年温和湿润"是错误的。温带大陆性气候特征是：冬冷夏热，气温年较差大，降水较少（集中夏季）。"全年温和湿润"是温带海洋性气候的特征（分布在中纬度大陆西岸）。'},
  {c:'地形',q:'极地旅游的快速增长（尤其是南极旅游）带来的问题是？',o:['完全没有问题，旅游业只有正面影响','游客增多→踩踏植被、惊扰野生动物、带入外来生物、垃圾和污染→对脆弱的极地生态系统造成不可逆损害','极地欢迎更多游客','旅游对极地气候有改善作用'],a:1,e:'南极旅游（年接待约7-10万人次）带来的问题：①踩踏脆弱地衣植被（恢复需数十年）②噪音干扰企鹅繁殖②引入外来物种（种子、昆虫随游客服装带入）③燃油泄漏风险（船舶事故）④排放（CO₂）。国际南极旅游运营商协会（IAATO）制定规范，但监管仍有难度。'},
  {c:'地形',q:'学习世界地理的意义是？',o:['只是考试需要','了解世界各地自然环境、文化差异、资源分布，培养全球视野，为国际合作和可持续发展做准备','世界地理只有记忆意义','与实际生活无关'],a:1,e:'学习世界地理的意义：①理解世界各地自然和人文环境差异②培养全球视野和跨文化理解③了解全球资源分布和环境问题（气候变化、生物多样性等）④为国际贸易、外交、旅游、科研等实践提供知识基础⑤理解人类与环境的相互关系（人地协调发展观）。'},
  {c:'地形',q:'关于气候变化应对，"共同但有区别的责任"原则是指？',o:['所有国家承担完全相同的减排义务','发达国家和发展中国家都有责任，但发达国家历史排放多，应承担更多义务（更大减排量和资金支持）','只有发达国家有责任','只有中国和美国有责任'],a:1,e:'"共同但有区别的责任"（CBDR）：《联合国气候变化框架公约》核心原则——所有国家都有应对气候变化的共同责任，但鉴于历史排放差异（发达国家工业化以来排放了大部分历史累积CO₂），发达国家应承担更多减排义务，并向发展中国家提供资金和技术支持。'},
  {c:'地形',q:'七年级地理中，"人地协调观"的含义是？',o:['人类对自然无限制的开发','人与自然必须保持和谐，人类活动应尊重自然规律，走可持续发展之路','自然对人类生活没有影响','人类应完全回归原始状态，停止一切开发'],a:1,e:'"人地协调观"是高中地理四大核心素养之一（七年级也初步涉及）：认识到人类与地理环境之间的相互依存关系，主张在开发利用自然资源的同时，注重保护环境、维持生态平衡，走可持续发展道路，反对"人定胜天"的极端思想，也反对"完全不开发"。'},
  {c:'地形',q:'学完七年级地理，以下哪种能力得到最大提升？',o:['数学计算能力','读图分析能力（地图判读、等高线分析、气候图分析）和地理空间思维能力','文学写作能力','体育运动能力'],a:1,e:'七年级地理的核心能力目标：①地图阅读和分析（地形图、气候图、人口分布图等）②地理空间思维（理解地理事物的分布规律及成因）③区域认知（认识不同地区的自然人文特征）④综合思维（分析地理问题的多因素相互关系）。这些是地理学习的基本素养。'}
);

